INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-07', E'오직 성령의 능력으로 다시 (스가랴 5장)', E'스가랴 5장', E'스가랴 선지자에게 주어진 다섯 번째와 여섯 번째 환상은 하나님께서 이스라엘 공동체를 정결케 하시는 과정을 보여줍니다. 날아가는 두루마리 환상은 온 땅에 내리는 저주의 선언으로, 도둑질하는 자와 거짓 맹세하는 자에 대한 심판을 담고 있습니다. 이 두루마리의 크기가 성막의 성소와 같은 치수(20×10규빗)라는 점은 의미심장합니다. 하나님의 거룩한 임재의 장소와 같은 크기의 심판이 온 땅을 덮는다는 것은, 거룩하신 하나님의 기준이 모든 삶의 영역에 적용됨을 보여줍니다.\n\n이어지는 에바 속의 여인 환상은 더욱 극적입니다. 에바는 곡물을 담는 큰 통으로, 경제 활동의 기본 단위를 상징합니다. 그 안에 앉아 있는 여인은 ''악'' 그 자체로 규정됩니다. 천사는 이 악을 에바 속에 가두고 납으로 봉인한 후, 날개 달린 두 여인이 그것을 시날 땅으로 옮겨가게 합니다. 시날은 바벨론 지역으로, 인간의 교만과 우상숭배의 발원지였습니다. 악이 제자리로 돌아가는 이 장면은 하나님께서 당신의 백성 가운데서 악을 완전히 제거하시는 정결 작업을 보여줍니다.\n\n성전 재건 중에 주어진 이 환상들은 단순히 건물을 세우는 것이 아니라 백성의 내면을 정결케 하는 것이 하나님의 관심사임을 드러냅니다. 외형적 종교 활동만으로는 충분하지 않습니다. 일상의 도덕적 삶과 진실한 언행이 하나님께서 원하시는 참된 예배의 기초가 됩니다. 하나님께서는 악을 제거하시되 단순히 파괴하시는 것이 아니라, 그것이 속한 곳으로 돌려보내심으로써 당신의 백성을 거룩한 공동체로 세워가십니다.', E'오늘의 핵심\n하나님께서는 날아가는 두루마리와 에바 속의 여인 환상을 통해 이스라엘 공동체의 도덕적, 영적 정결을 이루시며, 참된 성전은 깨끗한 삶의 터 위에 세워짐을 보여주십니다.\n\n묵상 질문\n1. 내 삶 속에서 하나님께서 제거하기 원하시는 ''도둑질''과 ''거짓 맹세''는 무엇일까요?\n2. 악을 에바에 가두어 시날로 보내시는 하나님의 정결케 하시는 은혜를 경험한 적이 있나요?\n3. 외적인 신앙생활과 내면의 거룩함이 일치하지 않는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-08', E'오직 성령의 능력으로 다시 (스가랴 6장)', E'스가랴 6장', E'네 병거의 환상을 통해 하나님께서는 온 땅을 다스리시는 주권자이심을 보여주십니다. 각기 다른 색의 말들이 끄는 네 병거는 하늘의 네 바람으로서, 온 세상의 주 앞에 서 있다가 사방으로 나아갑니다. 특별히 북쪽으로 나간 자들이 "북쪽에서 내 영을 쉬게 하였느니라"(슥 6:8)는 선언은 바벨론에 대한 심판이 완성되었음을 알려줍니다. 이는 포로 귀환 공동체에게 과거의 압제자들에 대한 하나님의 심판이 이루어졌다는 확신을 주는 메시지였습니다.\n\n이어지는 대관식 환상은 더욱 놀라운 미래를 보여줍니다. 바벨론에서 돌아온 헬대와 도비야, 여다야가 가져온 은과 금으로 면류관을 만들어 대제사장 여호수아의 머리에 씌우는 상징적 행위가 펼쳐집니다. 이는 단순한 제사장 임직식이 아니라, 메시아 시대에 대한 예언적 행동이었습니다. "싹"이라 불리는 이가 나타나 여호와의 전을 건축하고, 왕과 제사장의 직분을 동시에 수행하며 "이 둘 사이에 평화의 의논이 있으리라"는 약속은 다윗 왕조와 제사장직의 완전한 연합을 예고합니다.\n\n면류관을 성전에 보관하라는 명령은 이 약속이 미래에 성취될 것임을 상기시키는 기념물의 역할을 하게 됩니다. "먼 데 사람들이 와서 여호와의 전을 건축하리니"라는 예언은 이방인들까지 포함하는 하나님 나라의 확장을 보여줍니다. 스가랴는 절망에 빠진 귀환 공동체에게 현재의 작은 시작이 얼마나 위대한 미래로 이어질지를 보여주며, 그들의 순종이 하나님의 원대한 계획 안에서 귀중한 의미를 갖는다는 것을 깨닫게 합니다.', E'오늘의 핵심\n하나님께서는 온 땅을 다스리시는 주권과 함께, 왕이시며 제사장이신 메시아를 통해 완성될 구원의 청사진을 보여주십니다.\n\n묵상 질문\n1. 하나님의 주권이 온 세상에 미친다는 사실이 내게 어떤 위로를 주나요?\n2. 왕과 제사장의 역할을 동시에 감당하실 예수님을 어떻게 기다리고 있나요?\n3. 작은 순종이 하나님의 큰 계획에 쓰임받는다는 약속을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-09', E'천오백 년 사랑의 아쉬움 (말라기 1장)', E'말라기 1장', E'포로에서 돌아온 이스라엘은 더 이상 우상을 섬기지 않았습니다. 성전도 재건했고, 제사도 드렸습니다. 그런데 하나님께서는 이들에게 먼저 사랑을 고백하십니다. "내가 너희를 사랑하였노라." 아브라함을 부르신 때부터 지금까지, 출애굽과 광야, 가나안 정착과 포로 귀환까지 변함없이 사랑해 오신 분의 고백이었습니다. \n\n그런데 백성의 반응이 충격적입니다. "주께서 어떻게 우리를 사랑하셨나이까?" 이 질문 속에는 하나님의 사랑을 의심하는 냉소가 담겨 있었습니다. 하나님께서는 야곱을 택하시고 에돔을 심판하신 역사를 통해 당신의 사랑을 증명하셨지만, 이스라엘은 여전히 무감각했습니다.\n\n더 심각한 것은 제사장들의 타락이었습니다. 그들은 하나님을 아버지요 주인으로 부르면서도 정작 그분을 공경하지 않았습니다. 제단에는 눈먼 짐승, 저는 짐승, 병든 짐승이 올라갔습니다. 총독에게도 감히 드릴 수 없는 것들을 하나님께 드리면서도 "우리가 어떻게 주를 더럽게 하였나이까"라고 되묻는 뻔뻔함까지 보였습니다.\n\n하나님께서는 차라리 성전 문을 닫을 사람이 있기를 바라실 정도로 탄식하십니다. 형식적인 예배, 마지못해 드리는 제물, 번거로워하며 코웃음치는 태도가 하나님의 마음을 아프게 했습니다. 그럼에도 하나님은 놀라운 약속을 주십니다. "해 뜨는 곳에서부터 해 지는 곳까지의 이방 민족 중에서 내 이름이 크게 될 것이라." 이스라엘이 거부한 그 사랑을 온 세상이 받아들이게 될 것이라는 예언이었습니다.\n\n오늘 우리의 예배는 어떠한지 돌아보게 됩니다. 최선이 아닌 남은 것으로 드리는 예배, 의무감으로 채우는 시간이 되어버리진 않았는지 말입니다. 하나님의 변함없는 사랑 앞에 우리가 드릴 수 있는 것은 온전한 마음과 정성된 예배입니다.', E'오늘의 핵심\n하나님의 변함없는 사랑 고백에 이스라엘은 냉소로 응답했고, 제사장들은 형식적이고 경멸적인 예배로 하나님의 이름을 더럽혔습니다.\n\n묵상 질문\n1. 하나님의 사랑이 당연하게 느껴져서 감사를 잃어버린 적은 없나요?\n2. 내가 하나님께 드리는 예배와 헌신은 최선의 것인가요, 남은 것인가요?\n3. 형식적인 신앙생활에서 벗어나 진정한 예배자가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-10', E'천오백 년 사랑의 아쉬움 (말라기 2장)', E'말라기 2장', E'말라기 2장은 무너진 제사장직과 깨어진 언약의 민낯을 적나라하게 드러냅니다. 하나님께서는 특별히 제사장들을 향해 엄중한 경고의 메시지를 전하십니다. 그들은 백성과 하나님 사이의 중보자로 부름받았지만, 오히려 많은 사람을 율법에서 떠나게 만드는 걸림돌이 되어버렸습니다.\n\n하나님께서 레위 지파와 맺으신 언약은 "생명과 평강의 언약"이었습니다. 이 언약을 받은 초기의 레위인들은 하나님을 경외하며 진리의 법을 가르쳤고, 화평과 정직함으로 하나님과 동행하며 많은 사람을 죄악에서 돌이키게 했습니다. 제사장의 입술은 지식을 지켜야 하고, 백성들은 그들에게서 율법을 구해야 한다고 말씀하십니다. 제사장은 만군의 여호와의 사자이기 때문입니다.\n\n그러나 당시의 제사장들은 이 거룩한 부르심을 저버렸습니다. 그들은 옳은 길에서 떠났고, 율법을 행할 때 사람을 차별하며 편파적으로 대했습니다. 그 결과 하나님께서는 그들이 모든 백성 앞에서 멸시와 천대를 당하게 하셨다고 선언하십니다.\n\n제사장들의 타락은 백성 전체의 영적 타락으로 이어졌습니다. 유다 백성은 이방 신을 섬기는 여인들과 결혼하여 하나님의 성결을 욕되게 했고, 어려서 맺은 아내와의 언약을 파기하는 이혼이 만연했습니다. 하나님께서는 "나는 이혼하는 것과 옷으로 학대를 가리는 자를 미워하노라"고 분명히 말씀하십니다. 결혼 언약의 파괴는 단순한 개인의 문제가 아니라 하나님과 맺은 언약에 대한 불신실함을 보여주는 것이었습니다.\n\n가장 충격적인 것은 백성들의 영적 무감각입니다. 그들은 "모든 악을 행하는 자는 여호와의 눈에 좋게 보이며 그에게 기쁨이 된다"고 말하며, "정의의 하나님이 어디 계시냐"고 냉소적으로 묻습니다. 하나님의 공의를 의심하고 그분의 말씀을 괴롭게 하면서도 자신들의 잘못을 깨닫지 못했습니다.\n\n이 말씀은 오늘 우리에게도 깊은 성찰을 요구합니다. 영적 지도자들은 자신의 부르심을 진실하게 감당하고 있는지, 신앙 공동체는 하나님과의 언약을 신실하게 지키고 있는지, 그리고 우리의 신앙이 형식적이고 냉소적으로 변질되지는 않았는지 돌아보게 합니다.', E'오늘의 핵심\n하나님께서는 무너진 제사장직과 깨어진 언약 관계를 통해 이스라엘의 영적 타락을 고발하시며, 참된 회복은 하나님과의 언약에 신실함으로 돌아가는 것임을 보여주십니다.\n\n묵상 질문\n1. 내가 받은 영적 책임과 부르심을 신실하게 감당하고 있는지 점검해 보셨나요?\n2. 하나님과의 언약, 사람과의 약속을 가볍게 여기거나 파기한 적은 없었나요?\n3. 신앙생활이 형식적이 되어 하나님의 공의와 사랑을 의심하게 된 순간은 언제였나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-12', E'천오백 년 사랑의 아쉬움 (말라기 3장)', E'말라기 3장', E'말라기 3장은 하나님의 변하지 않는 성품과 백성의 변덕스러운 마음 사이의 긴장을 보여주고 있습니다. 포로 귀환 후 백성들은 형식적인 예배는 드렸지만, 마음은 하나님께로부터 멀어져 있었습니다. 그들은 십일조와 봉헌물을 아끼며 하나님의 것을 도둑질하고도 "우리가 어떻게 주의 것을 도둑질하였나이까"라고 반문합니다. 더 나아가 "하나님을 섬기는 것이 헛되다"는 냉소적인 말까지 서슴지 않습니다.\n\n이런 백성들에게 하나님은 언약의 사자를 보내실 것을 약속하십니다. 그러나 그 날은 단순한 구원의 날만이 아닙니다. "그는 금을 연단하는 자의 불과 표백하는 자의 잿물과 같을 것"이라는 말씀처럼, 정결케 하시는 심판의 과정을 포함하고 있습니다. 특히 레위 자손들, 즉 하나님을 섬기는 자들부터 먼저 연단하실 것을 말씀하십니다. 이는 하나님께서 당신의 백성을 포기하지 않으시고 끝까지 정결케 하시려는 사랑의 표현입니다.\n\n놀라운 것은 이 모든 불신앙과 배반에도 불구하고 하나님께서 "나 여호와는 변하지 아니하나니"라고 선언하시는 것입니다. 바로 이 변치 않는 성품 때문에 "야곱의 자손들아 너희가 소멸되지 아니하느니라"고 말씀하십니다. 백성의 신실하지 못함이 하나님의 신실하심을 바꿀 수 없었던 것입니다.\n\n그러면서도 하나님은 구체적인 회복의 길을 제시하십니다. "너희의 온전한 십일조를 창고에 들여 나의 집에 양식이 있게 하고 그것으로 나를 시험하여 내가 하늘 문을 열고 너희에게 복을 쌓을 곳이 없도록 붓지 아니하나 보라"는 도전은 형식적 종교가 아닌 실제적 헌신을 요구하시는 것입니다. 십일조는 단순한 물질의 문제가 아니라 하나님을 향한 신뢰와 순종의 표현이었습니다.\n\n말라기는 냉랭해진 신앙 공동체 가운데서도 "여호와를 경외하는 자들"이 있었음을 기록합니다. 그들은 서로 대화하며 신앙을 지켜갔고, 하나님은 그들을 위해 "기념책"에 기록하셨습니다. 이들은 하나님의 "특별한 소유"가 될 것이며, 아들을 아끼듯 아낌을 받을 것입니다. 어두운 시대에도 신실함을 지키는 남은 자들을 통해 하나님의 구원 역사가 이어지는 것을 봅니다.', E'오늘의 핵심\n하나님은 백성의 냉소적 불신앙에도 불구하고 변치 않는 사랑으로 그들을 연단하시며, 진실한 헌신으로 돌아오기를 기다리십니다.\n\n묵상 질문\n1. 나도 모르게 하나님의 것을 도둑질하며 살고 있는 영역은 무엇일까요?\n2. "하나님을 섬기는 것이 헛되다"는 생각이 들 때, 나는 어떻게 신앙을 지켜가고 있나요?\n3. 하나님의 변치 않는 성품이 오늘 나에게 주는 위로와 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-13', E'천오백 년 사랑의 아쉬움 (말라기 4장)', E'말라기 4장', E'말라기의 마지막 장은 구약 성경 전체의 마침표이자 새로운 시작을 예고하는 장엄한 선언입니다. 하나님께서는 심판과 구원의 두 얼굴을 동시에 보여주십니다. "용광로 불 같은 날"이 이를 것이며, 그날에 교만한 자와 악을 행하는 자는 지푸라기처럼 타버릴 것이라고 경고하십니다. 뿌리와 가지까지 남김없이 사라질 것이라는 표현은 심판의 철저함을 보여줍니다.\n\n그러나 같은 날이 하나님을 경외하는 자들에게는 전혀 다른 의미로 다가옵니다. "공의로운 해가 떠올라서 치료하는 광선을 비추리니"라는 약속은 심판의 불이 구원의 빛으로 변화됨을 보여줍니다. 외양간에서 막 풀려난 송아지가 기쁨에 뛰는 것처럼, 구원받은 백성이 누릴 자유와 기쁨을 생생하게 그려냅니다. 이는 단순한 구원을 넘어 완전한 회복과 치유의 약속입니다.\n\n하나님께서는 이 약속과 함께 두 가지 중요한 말씀을 더하십니다. 먼저 호렙산에서 모세에게 주신 율법을 기억하라고 하십니다. 이는 하나님의 백성이 걸어야 할 길이 이미 분명히 제시되어 있음을 상기시킵니다. 그리고 엘리야를 보내겠다는 약속으로 구약을 마무리하십니다. 아버지와 자녀의 마음이 서로에게로 돌아오는 화해의 역사가 일어날 것입니다.\n\n이 마지막 장은 400년의 침묵기를 앞두고 주어진 약속이었습니다. 그리고 이 약속은 광야에서 외치는 세례 요한의 음성으로, 궁극적으로는 예수 그리스도의 오심으로 성취됩니다. 심판의 불꽃 같았던 하나님의 공의가 십자가에서 사랑의 불꽃으로 타올랐고, 치료하는 광선은 부활의 새벽빛으로 온 세상을 비추게 되었습니다.\n\n오늘도 우리는 이 두 가지 실재 사이에 서 있습니다. 하나님의 공의로운 심판이 엄연히 존재하지만, 그리스도 안에서 치료와 회복의 빛이 우리를 비추고 있습니다. 그러므로 우리는 하나님을 경외하며 그분의 말씀을 기억하고, 화해의 사역자로 부르심을 받았음을 잊지 말아야 합니다.', E'오늘의 핵심\n구약의 마지막 장은 심판과 구원의 날을 예고하며, 오실 메시아를 통한 완전한 회복을 약속합니다.\n\n묵상 질문\n1. 동일한 하나님의 날이 어떤 이에게는 심판이, 어떤 이에게는 구원이 되는 이유는 무엇일까요?\n2. 하나님을 경외한다는 것이 내 일상에서 구체적으로 어떻게 나타나고 있나요?\n3. 아버지와 자녀의 마음이 돌이켜져야 할 관계가 내 주변에 있다면 어떻게 화해의 다리가 될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-14', E'약속의 결정체, 예수', E'마태복음 1장', E'마태복음 1장은 아브라함부터 다윗, 다윗부터 바벨론 포로기, 바벨론 포로기부터 예수 그리스도에게로 이어지는 계보를 정리하고 있습니다. 마태는 1절에 아브라함과 다윗, 그리고 예수님, 이렇게 세 명의 이름으로 구약 2천 년을 담아 내고 있습니다. 또한 많은 왕들 중 유독 다윗에게만 ''왕''이라는 칭호를 붙여 다윗을 최대한 높여주었습니다. 그리고 이 족보에는 5명의 여인이 나오는데, 다른 사람들은 모두 이름으로 적은 것과 달리, 유독 밧세바를 ''우리야(우리아)의 아내''라고 적고 있습니다. 우리야의 아내 밧세바를 범한 잘못을 감추고 싶어서 충직한 신하였던 우리야를 전쟁으로 내몰아 죽인 다윗의 죄를 드러낸 것입니다. 이는 유대인들이 그토록 추앙하는 위대한 왕 다윗이라 할지라도 예수님의 십자가 보혈로 죄 사함을 받아야 할 한 사람의 죄인에 불과하다는 것을 강조하기 위해서였습니다. 모든 사람이 그분의 이름 앞에 꿇어 경배함이 마땅하다는 것이 마태가 하고 싶은 이야기입니다.\n예수님께서 유대 땅 베들레헴에 나실 때 동방박사들과 들녘의 목자들이 찾아와 아기 예수님의 탄생을 축하하며 기뻐했습니다. 예수님께서는 그 후 나사렛에서 자라신 후 세례 요한에게 세례를 받으시고 천국을 전파하시며 공생애를 시작하십니다.', E'오늘의 핵심\n하나님께서는 태초부터 계획하신 온 인류 구원의 약속을 실현하시고자 독생자 예수 그리스도를 이 땅에 보내십니다.\n\n묵상 질문\n하나님은 왜 불완전한 사람들의 계보 속에서 예수님을 약속하셨을까요?\n예수님의 족보에 죄인들이 포함된 것은 내 삶에 어떤 의미가 있을까요?\n하나님의 약속이 나를 통해 어떻게 이루어질 수 있도록 기도할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-15', E'산상수훈 (마태복음 5장)', E'마태복음 5장', E'갈릴리 산 위에서 예수님이 입을 여시며 하나님 나라의 새로운 질서가 선포됩니다. 산상수훈의 시작인 팔복은 세상이 추구하는 가치관을 완전히 뒤집어놓습니다. 심령이 가난한 자, 애통하는 자, 온유한 자가 복이 있다는 선언은 당시 청중들에게 충격이었을 것입니다. 세상은 부유함과 웃음과 강함을 복의 조건으로 여기지만, 예수님은 자신의 연약함을 인정하고 하나님께 전적으로 의지하는 자들이야말로 천국을 소유한다고 가르치십니다.\n\n예수님은 이렇게 복을 받은 자들의 정체성을 "너희는 세상의 소금이니... 너희는 세상의 빛이라"(마 5:13-14)고 규정하십니다. 소금은 부패를 막고 맛을 내며, 빛은 어둠을 몰아내고 길을 비춥니다. 그리스도인의 삶이 세상 속에서 갖는 본질적 기능을 보여주는 비유입니다. 그러나 맛을 잃은 소금, 감추어진 빛은 아무 소용이 없습니다. 착한 행실로 빛을 비추되, 그 목적이 자기 영광이 아니라 하늘 아버지께 영광을 돌리는 것이어야 함을 분명히 하십니다.\n\n이어지는 가르침에서 예수님은 율법의 참된 의미를 밝히십니다. 율법을 폐하러 오신 것이 아니라 완전하게 하러 오셨다는 선언과 함께, 외적 행위를 넘어 마음의 동기를 다루십니다. 살인하지 말라는 계명을 형제에 대한 분노의 문제로, 간음하지 말라는 계명을 음욕을 품는 마음의 문제로 확대하여 해석하십니다. 서기관과 바리새인들이 추구했던 외적이고 형식적인 의가 아니라, 마음에서 우러나오는 진정한 의를 요구하시는 것입니다.\n\n특별히 원수 사랑의 명령은 산상수훈의 절정을 이룹니다. "너희 원수를 사랑하며 너희를 박해하는 자를 위하여 기도하라"는 말씀은 인간의 본성과 상식을 뛰어넘는 하나님 나라의 윤리입니다. 악인과 선인에게 똑같이 해를 비추시고 비를 내리시는 하나님의 무차별적 사랑을 본받으라는 것입니다. 이것이 바로 "하늘에 계신 너희 아버지의 온전하심과 같이 너희도 온전하라"는 궁극적 부르심의 의미입니다.', E'오늘의 핵심\n예수님은 팔복을 통해 하나님 나라 백성의 성품을 제시하시고, 소금과 빛의 비유로 그들의 사명을 보여주시며, 율법의 참된 정신인 마음의 의와 원수 사랑을 가르치십니다.\n\n묵상 질문\n1. 나는 어떤 면에서 심령이 가난하며, 그것이 어떻게 천국을 소유하는 복이 될 수 있을까요?\n2. 내 삶이 소금의 맛을 잃지 않고 빛을 발하려면 무엇을 점검해야 할까요?\n3. 지금 내게 있는 분노나 미움을 예수님의 원수 사랑 명령 앞에 어떻게 내려놓을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-16', E'산상수훈 (마태복음 6장)', E'마태복음 6장', E'마태복음 6장은 산상수훈의 중심부로서, 예수님께서 참된 의와 경건의 삶이 무엇인지 가르쳐 주십니다. 특히 ''은밀한 중에 보시는 아버지''라는 표현이 반복되면서, 하나님과의 관계가 외적인 종교 행위가 아닌 내면의 진실함에 기초해야 함을 보여줍니다.\n\n예수님은 먼저 구제와 기도와 금식을 예로 들어 경건의 동기를 점검하십니다. 외식하는 자들은 회당과 거리에서 나팔을 불며 구제하고, 사람들이 보는 곳에서 기도하며, 금식할 때 일부러 얼굴을 흉하게 합니다. 그들의 목적은 사람에게 칭찬받는 것이었고, 예수님은 "그들은 자기 상을 이미 받았느니라"고 말씀하십니다. 반면 하나님께서 기뻐하시는 것은 오른손이 하는 것을 왼손이 모르게 하는 구제, 골방에서 드리는 기도, 머리에 기름 바르고 얼굴을 씻으며 하는 금식입니다. 이것은 단순히 비밀스럽게 하라는 뜻이 아니라, 오직 하나님만을 의식하며 살라는 가르침입니다.\n\n이어서 예수님은 제자들에게 주기도문을 가르쳐 주십니다. 이방인들처럼 중언부언하지 말고, 하나님의 이름과 나라와 뜻을 먼저 구하며, 일용할 양식과 용서와 시험으로부터의 보호를 구하라고 하십니다. 특별히 용서에 대해서는 "너희가 사람의 잘못을 용서하면 너희 하늘 아버지께서도 너희 잘못을 용서하시려니와"(마 6:14)라고 강조하시면서, 하나님과의 관계가 이웃과의 관계와 분리될 수 없음을 가르치십니다.\n\n마지막으로 예수님은 보물을 하늘에 쌓으라고 말씀하시며, 하나님과 재물을 겸하여 섬길 수 없다고 선언하십니다. 그리고 공중의 새와 들의 백합화를 통해 하늘 아버지의 돌보심을 신뢰하라고 가르치십니다. 염려는 이방인들이 하는 것이며, 하나님의 자녀들은 먼저 그의 나라와 의를 구해야 합니다.\n\n마태복음 6장이 우리에게 던지는 도전은 분명합니다. 신앙생활이 사람들의 인정을 받기 위한 종교적 퍼포먼스가 되어서는 안 된다는 것입니다. 은밀한 중에 계신 아버지께서는 우리의 모든 필요를 아시고, 우리의 진심을 보십니다. 그분 앞에서 진실한 마음으로 살아갈 때, 비로소 우리는 참된 하나님 나라 백성의 삶을 살 수 있습니다.', E'오늘의 핵심\n예수님은 사람에게 보이려는 외식적인 경건이 아닌, 은밀한 중에 보시는 하나님 아버지 앞에서의 진실한 삶을 가르치십니다.\n\n묵상 질문\n1. 나의 구제와 기도와 금식은 누구를 향한 것인가요? 사람의 인정입니까, 하나님의 기쁨입니까?\n2. 주기도문을 통해 내가 먼저 구해야 할 것과 나중에 구할 것의 우선순위를 어떻게 정리하시겠습니까?\n3. 내일을 염려하는 대신 오늘 하나님의 나라와 의를 구하기 위해 무엇을 실천하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-17', E'산상수훈 (마태복음 7장)', E'마태복음 7장', E'산상수훈의 마지막 장인 마태복음 7장은 하나님 나라 백성이 일상에서 실천해야 할 구체적인 삶의 원칙들을 제시합니다. 예수님은 먼저 비판에 대해 경고하십니다. "너희가 비판하는 그 비판으로 너희가 비판을 받을 것"(마 7:2)이라는 말씀은 우리가 다른 사람을 판단하는 그 잣대가 결국 우리 자신에게 돌아온다는 엄중한 진리를 담고 있습니다. 형제의 눈 속에 있는 티와 내 눈 속에 있는 들보의 비유는 우리가 얼마나 자기 성찰 없이 타인을 정죄하기 쉬운지를 보여줍니다.\n\n이어지는 기도에 대한 가르침은 하늘 아버지의 성품을 드러냅니다. 예수님은 구하고, 찾고, 두드리라고 말씀하시며, 악한 부모도 자녀에게 좋은 것을 줄 줄 아는데 하물며 하늘 아버지께서 구하는 자에게 좋은 것으로 주시지 않겠느냐고 반문하십니다. 이는 하나님께서 우리의 필요를 아시고 응답하시는 선하신 아버지라는 확신을 심어줍니다.\n\n그러나 예수님은 동시에 좁은 문으로 들어가라고 도전하십니다. 멸망으로 인도하는 문은 크고 넓어서 많은 사람이 그리로 가지만, 생명으로 인도하는 문은 좁고 그 길이 협착합니다. 이는 신앙의 길이 결코 쉽지 않으며, 의도적인 선택과 헌신이 필요함을 보여줍니다. \n\n특별히 주목할 것은 거짓 선지자에 대한 경고와 열매로 나무를 아는 원리입니다. 겉모습이 아니라 삶의 열매로 진짜를 분별해야 합니다. 더 나아가 예수님은 "주여 주여" 부르며 주의 이름으로 많은 일을 행했다고 주장하는 사람들에게도 "내가 너희를 도무지 알지 못한다"고 말씀하실 수 있음을 경고하십니다. 중요한 것은 종교적 활동이 아니라 하늘 아버지의 뜻을 행하는 삶입니다.\n\n마지막으로 예수님은 말씀을 듣고 행하는 자와 듣기만 하는 자의 차이를 반석 위의 집과 모래 위의 집으로 비유하십니다. 인생의 폭풍이 몰아칠 때, 우리 신앙의 기초가 무엇인지가 드러납니다. 말씀을 듣는 것에서 그치지 않고 실천하는 삶이야말로 견고한 신앙의 토대가 됩니다.', E'오늘의 핵심\n예수님은 비판하지 말고, 끈질기게 구하며, 좁은 문으로 들어가고, 열매로 분별하며, 무엇보다 말씀을 듣고 행하는 삶을 살라고 가르치십니다.\n\n묵상 질문\n1. 나는 형제의 티를 지적하기 전에 내 눈의 들보를 먼저 보고 있나요?\n2. 좁은 문으로 들어가는 삶을 위해 내가 포기해야 할 것은 무엇인가요?\n3. 오늘 들은 말씀 중에 즉시 실천해야 할 것은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-19', E'예수의 이적과 열두 제자 선택 (마태복음 8장)', E'마태복음 8장', E'산상수훈을 마치신 예수님께서 산에서 내려오시자 수많은 무리가 따릅니다. 그때 한센병 환자가 나아와 절하며 간구합니다. 당시 한센병 환자는 부정한 자로 여겨져 사람들에게 가까이 갈 수도 없었는데, 예수님께서는 손을 내밀어 그에게 직접 대시며 고쳐주십니다. 이는 율법이 금하는 접촉이었지만, 예수님의 사랑은 정결의 율법보다 더 큰 능력이었습니다.\n\n가버나움에서 만난 로마 백부장의 믿음은 더욱 놀라웠습니다. 이방인이면서도 그는 예수님의 권위를 정확히 이해하고 있었습니다. "다만 말씀으로만 하옵소서"(마 8:8)라는 그의 고백에서 우리는 말씀의 권위에 대한 온전한 신뢰를 봅니다. 예수님께서는 이스라엘 중에서도 이만한 믿음을 보지 못하셨다고 감탄하십니다. 하나님 나라는 혈통이나 민족이 아닌 믿음으로 들어가는 곳임을 보여주는 장면입니다.\n\n베드로의 장모를 고치신 후 저물 무렵, 사람들이 병든 자들을 데려왔을 때도 예수님께서는 한 사람도 돌려보내지 않으셨습니다. 이는 이사야 선지자가 예언한 "우리의 연약한 것을 친히 담당하시고 병을 짊어지셨다"는 말씀의 성취였습니다. \n\n그러나 예수님을 따르는 길은 결코 안락하지 않습니다. 여우도 굴이 있고 새도 거처가 있지만 인자는 머리 둘 곳이 없다고 말씀하십니다. 제자도의 길은 희생과 헌신을 요구합니다. 폭풍 속에서 주무시는 예수님의 모습은 제자들에게 큰 도전이 되었고, 가다라 지방에서 귀신 들린 자들을 고치신 일은 오히려 그 지방 사람들에게 두려움을 주어 예수님을 떠나가시도록 간구하게 만들었습니다.\n\n이 모든 일들은 예수님께서 단순히 기적을 행하는 분이 아니라, 인간의 고통과 연약함을 깊이 이해하시고 친히 담당하시는 메시아이심을 보여줍니다. 그분의 치유는 육체만이 아닌 영혼까지 온전케 하시는 구원의 손길이었습니다.', E'오늘의 핵심\n예수님께서는 말씀의 권위로 병자들을 고치시며, 사회에서 소외된 자들을 직접 만지시고 치유하심으로써 하나님의 긍휼과 구원의 능력을 나타내셨습니다.\n\n묵상 질문\n1. 한센병 환자에게 손을 대신 예수님처럼, 우리는 소외된 이웃을 어떻게 품을 수 있을까요?\n2. 백부장의 믿음처럼 말씀의 권위를 온전히 신뢰하는 믿음이 내게 있나요?\n3. 예수님을 따르는 제자도의 길에서 내가 내려놓아야 할 안락함은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-20', E'예수의 이적과 열두 제자 선택 (마태복음 9장)', E'마태복음 9장', E'갈릴리 호수를 건너 가버나움으로 돌아오신 예수님께 침상에 누운 중풍병자가 실려옵니다. 예수님께서는 병자를 메고 온 사람들의 믿음을 보시고 놀라운 선언을 하십니다. "작은 자야 안심하라 네 죄 사함을 받았느니라"(마 9:2). 육체의 치유를 구하러 온 이들에게 예수님께서는 먼저 영혼의 문제를 다루십니다. 이는 인간의 가장 근본적인 문제가 죄임을 보여주는 것이었습니다. 서기관들이 속으로 신성모독이라 비난하자, 예수님께서는 죄 사함의 권세와 병 고침의 권세가 모두 자신에게 있음을 중풍병자의 치유를 통해 증명하셨습니다.\n\n세관에 앉아있던 마태를 부르신 일은 예수님의 사역 방향을 분명히 보여줍니다. 당시 세리는 로마의 앞잡이로 민족의 배신자 취급을 받았습니다. 그런 마태의 집에서 세리와 죄인들과 함께 식사하시는 예수님을 바리새인들이 비난하자, 예수님께서는 의사가 병든 자에게 필요하듯 자신은 죄인을 부르러 왔다고 선포하십니다. 이어서 금식 논쟁을 통해 새로운 시대가 도래했음을 새 포도주와 새 부대의 비유로 설명하십니다. 예수님과 함께하는 지금은 혼인 잔치와 같은 기쁨의 때이며, 율법주의적 종교 체계로는 담을 수 없는 새로운 은혜의 시대가 열렸음을 선언하신 것입니다.\n\n회당장 야이로의 딸을 살리러 가시는 길에 열두 해 동안 혈루증을 앓던 여인이 예수님의 옷자락을 만집니다. 부정한 질병으로 소외되었던 이 여인의 믿음을 예수님께서는 공개적으로 인정하시며 치유하셨습니다. 죽은 소녀를 살리시고, 두 맹인의 눈을 뜨게 하시며, 귀신 들려 말 못하는 사람을 고치시는 일련의 기적들은 메시아 시대가 도래했음을 보여주는 표적들이었습니다. 그러나 바리새인들은 끝까지 예수님을 귀신의 왕을 의지한다고 비방합니다. 예수님께서는 이런 반대에도 불구하고 목자 없는 양 같은 무리를 불쌍히 여기시며 천국 복음을 전파하시고 병자를 고치셨습니다. 추수할 것은 많으나 일꾼이 적다는 말씀은 제자들을 향한 부르심이자 오늘 우리를 향한 초대이기도 합니다.', E'오늘의 핵심\n예수님께서는 죄 사함의 권세를 가지신 메시아로서 소외된 자들을 찾아가시고, 새로운 은혜의 시대를 여시며, 무리를 불쌍히 여기시는 참 목자의 모습을 보여주십니다.\n\n묵상 질문\n1. 예수님께서 중풍병자에게 먼저 죄 사함을 선언하신 이유는 무엇일까요?\n2. 세리와 죄인들과 함께 식사하신 예수님의 모습이 오늘날 교회에 주는 도전은 무엇인가요?\n3. 목자 없는 양 같은 이웃을 위해 나는 어떤 일꾼이 되어야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-21', E'예수의 이적과 열두 제자 선택 (마태복음 10장)', E'마태복음 10장', E'예수님께서는 열두 제자를 부르시며 그들에게 놀라운 권능을 주십니다. 더러운 귀신을 쫓아내고 모든 병과 연약함을 고치는 권세를 부여받은 제자들은 이제 예수님의 동역자가 되었습니다. 마태는 열두 사도의 이름을 기록하면서 자신을 ''세리 마태''라고 소개합니다. 세리라는 신분이 유대 사회에서 얼마나 천대받는 직업이었는지를 생각하면, 이는 자신의 과거를 부끄러워하면서도 그런 자신을 제자로 부르신 예수님께 대한 깊은 감사의 표현이었습니다.\n\n예수님께서는 제자들을 파송하시면서 먼저 "이스라엘 집의 잃어버린 양에게로 가라"고 명하십니다. 이방인의 길로도, 사마리아인의 고을에도 가지 말라는 말씀은 구원의 우선순위를 보여주는 것이었습니다. 제자들은 천국이 가까이 왔다는 메시지를 전하며, 병자를 고치고 죽은 자를 살리며 귀신을 쫓아내는 사역을 감당해야 했습니다. "거저 받았으니 거저 주라"는 예수님의 말씀은 복음 전파의 본질을 보여줍니다.\n\n그러나 예수님께서는 제자들이 당할 환난도 분명히 예고하십니다. 공회에 넘겨지고, 회당에서 채찍질당하며, 총독들과 임금들 앞에 끌려갈 것이라는 말씀은 복음 전파의 길이 결코 평탄하지 않음을 보여줍니다. 심지어 가족들조차 대적하여 죽음에 내어줄 것이라는 예언은 제자도의 극한 상황을 묘사합니다. 그럼에도 불구하고 예수님께서는 "두려워하지 말라"고 거듭 강조하십니다. 참새 한 마리도 하나님의 허락 없이는 땅에 떨어지지 않으며, 제자들의 머리털까지 세신 바 되었다는 말씀은 하나님의 세밀한 돌보심을 확증해 줍니다.\n\n예수님을 따르는 길은 자기 십자가를 지는 길입니다. 가족보다 예수님을 더 사랑해야 하며, 자기 목숨을 잃을 각오가 되어 있어야 합니다. 이는 단순한 희생이 아니라 영원한 생명을 얻는 역설적인 길입니다. 제자들을 영접하는 것이 곧 예수님을 영접하는 것이며, 작은 자에게 냉수 한 그릇을 주는 것조차도 하늘의 상급이 있다는 약속은 하나님 나라의 가치관을 보여줍니다.', E'오늘의 핵심\n예수님께서는 열두 제자를 부르시고 권능을 주시며 파송하시면서, 복음 전파의 사명과 그에 따르는 희생, 그리고 하나님의 돌보심과 영원한 상급을 약속하십니다.\n\n묵상 질문\n1. 세리였던 마태를 제자로 부르신 예수님의 은혜가 나의 삶에는 어떻게 나타나고 있나요?\n2. 복음을 위해 감당해야 할 희생과 고난 앞에서도 두려워하지 않을 수 있는 이유는 무엇일까요?\n3. 오늘 내가 냉수 한 그릇을 나누어야 할 ''작은 자''는 누구인지 기도하며 찾아보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-22', E'예수의 갈릴리 사역', E'마태복음 16장', E'아의 외치는 소리로 자신의 사명을 잘 감당했던 세례 요한은 헤롯이 동생의 아내를 취한 것을 비판한 일로 옥에 갇히고 헤로디아의 악한 계획으로 인해 죽임을 당하게 됩니다. 마태복음 14장에는 예수님을 따르던 큰 무리에게 행하신 예수님의 기적이 기록되어 있습니다. 예수님께서 하루 종일 말씀을 전하신 어느 날 날이 저물자 제자들이 와서 "무리를 보내어 마을에 들어가 먹을 것을 사 먹게 하소서"(마 14:15)라고 말합니다. 예수님께서 그들에게 먹을 것을 주라고 말씀하시자 제자들은 떡 다섯 개와 물고기 두 마리밖에 없다고 대답합니다. 예수님께서는 이 떡과 물고기들을 가지고 축사하신 후 제자들을 시켜서 나누어주게 하십니다.\n말씀을 듣던 무리에게 오병이어의 기적을 베푸셨던 이후 바다를 건너 제자들과 함께 게네사렛 땅으로 가십니다. 그리고 그곳의 많은 병든 자들이 예수님께 고침을 받습니다. 예수님께서는 귀신 들린 아이와 다리 저는 사람, 맹인과 말 못하는 사람 등 많은 이들을 고쳐주십니다. 예수님의 가르침과 이적을 경험한 많은 무리가 이를 놀랍게 여기며 하나님께 영광을 돌립니다.', E'오늘의 핵심\n예수님께서 보여주셨던 많은 기적은 사람들에게 하나님의 말씀을 전하고 약한 이웃들을 사랑하기 위한 그분의 방법이었습니다.\n\n묵상 질문\n예수님은 부족함 속에서도 감사하시고 나누시는 분이셨음을 어떻게 느끼셨나요?\n내가 가진 작은 것으로 누군가를 도울 수 있다고 믿으시나요?\n예수님처럼 부족함 속에서도 감사하고 나누는 사람이 되길 원하시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-23', E'예루살렘을 향한 여정 (마태복음 17장)', E'마태복음 17장', E'마태복음 17장은 예수님의 영광과 제자들의 연약함이 극명하게 대조되는 장면을 보여줍니다. 높은 산 위에서 예수님은 변형되어 얼굴이 해같이 빛나고 옷이 빛과 같이 희어지셨습니다. 모세와 엘리야가 나타나 예수님과 대화하는 가운데, 하늘에서는 "이는 내 사랑하는 아들이요 내 기뻐하는 자니 너희는 그의 말을 들으라"는 음성이 들려왔습니다. 이 변화산 사건은 예수님이 구약에서 약속된 메시아이심을 분명히 드러내는 순간이었습니다.\n\n베드로는 그 영광스러운 광경에 압도되어 "주여 우리가 여기 있는 것이 좋사오니"라고 말하며 초막을 짓겠다고 제안합니다. 그의 마음은 이해할 만합니다. 누가 그런 영광의 순간을 떠나고 싶겠습니까? 그러나 예수님은 제자들과 함께 산을 내려오셨습니다. 산 아래에는 간질병으로 고통받는 아이와 그를 고치지 못해 좌절한 제자들이 있었기 때문입니다.\n\n예수님은 "믿음이 없고 패역한 세대여"라고 탄식하시면서도 그 아이를 고쳐주십니다. 제자들이 왜 자신들은 고치지 못했는지 묻자, 예수님은 믿음이 작기 때문이라고 답하십니다. 겨자씨만한 믿음이라도 있으면 산을 옮길 수 있다는 말씀은, 믿음의 크기보다 그 진정성이 중요함을 가르쳐 주십니다.\n\n이어서 예수님은 자신이 사람들의 손에 넘겨져 죽임을 당하고 사흘 만에 살아날 것을 다시 예고하십니다. 영광의 변화산에서 내려온 직후에 십자가의 길을 말씀하신 것입니다. 이는 예수님의 영광이 고난과 분리될 수 없음을 보여줍니다. 참된 영광은 섬김과 희생을 통해 완성되는 것입니다.\n\n마지막으로 성전세 사건은 예수님이 하나님의 아들로서 성전세를 낼 의무가 없으심에도 불구하고, 사람들이 실족하지 않도록 세금을 내신 모습을 보여줍니다. 권리를 주장하기보다 타인을 배려하는 겸손한 섬김의 본을 보여주신 것입니다. 산 위의 영광과 산 아래의 섬김, 이 두 모습이 우리가 따라가야 할 예수님의 참모습입니다.', E'오늘의 핵심\n변화산에서 영광을 드러내신 예수님은 산 아래로 내려와 고통받는 이들을 치유하시고, 십자가의 길을 예고하시며, 겸손히 섬기는 본을 보여주십니다.\n\n묵상 질문\n1. 내가 머물고 싶어하는 ''영광의 자리''는 어디이며, 주님이 부르시는 ''섬김의 현장''은 어디인가요?\n2. 겨자씨만한 믿음으로도 산을 옮길 수 있다는 말씀이 오늘 내 삶에 주는 위로와 도전은 무엇인가요?\n3. 예수님처럼 나의 권리보다 타인의 유익을 먼저 생각해야 할 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-24', E'예루살렘을 향한 여정 (마태복음 18장)', E'마태복음 18장', E'마태복음 18장은 예수님께서 천국의 백성이 가져야 할 삶의 원칙을 가르치시는 말씀입니다. 제자들이 "천국에서는 누가 크니이까"라고 묻자, 예수님은 한 어린아이를 그들 가운데 세우시고 충격적인 답변을 주십니다. 천국에서 큰 자는 어린아이와 같이 자기를 낮추는 사람이라는 것입니다. 당시 사회에서 어린아이는 가장 무력하고 보잘것없는 존재로 여겨졌습니다. 그런데 예수님은 바로 그런 어린아이의 겸손함과 의존성이야말로 천국 백성의 본질적 특성이라고 가르치십니다.\n\n이어서 예수님은 작은 자들을 실족시키는 것에 대해 엄중히 경고하십니다. 연자맷돌을 목에 달고 바다에 빠뜨려지는 것이 낫다는 표현은 그 죄의 무게가 얼마나 큰지를 보여줍니다. 하나님께서는 길 잃은 양 한 마리를 찾아 나서는 목자의 비유를 통해 작은 자 하나라도 잃어버리는 것이 아버지의 뜻이 아님을 분명히 하십니다. 아흔아홉 마리를 산에 두고서라도 길 잃은 한 마리를 찾아 나서는 목자의 마음, 그것이 바로 하나님 아버지의 마음입니다.\n\n용서에 관한 베드로의 질문은 우리 모두의 고민을 대변합니다. "일곱 번까지 용서하면 충분하지 않습니까?" 그러나 예수님의 대답은 "일곱 번을 일흔 번까지라도" 용서하라는 것이었습니다. 이는 단순히 490번이라는 숫자가 아니라 무한한 용서를 의미합니다. 만 달란트 탕감받은 종의 비유는 이 가르침을 더욱 분명하게 합니다. 만 달란트는 약 6천 만 데나리온으로, 한 사람이 평생 일해도 갚을 수 없는 천문학적 액수입니다. 하나님께서 우리에게 베푸신 용서가 이토록 크다면, 우리가 형제의 작은 허물을 용서하지 못할 이유가 있겠습니까?\n\n천국은 세상의 가치관과 정반대입니다. 높아지려는 자는 낮아지고, 낮추는 자가 높아집니다. 작은 자를 귀하게 여기고, 잃어버린 자를 끝까지 찾아가며, 형제의 허물을 한없이 용서하는 곳입니다. 이것이 예수님께서 십자가로 보여주신 천국의 원리이며, 오늘 우리가 살아내야 할 삶의 방식입니다.', E'오늘의 핵심\n예수님은 어린아이처럼 자기를 낮추고, 작은 자를 귀히 여기며, 형제를 무한히 용서하는 것이 천국 백성의 삶이라고 가르치십니다.\n\n묵상 질문\n1. 내가 높아지려고 애쓰는 영역은 무엇이며, 그곳에서 어떻게 자신을 낮출 수 있을까요?\n2. 하나님께 받은 용서의 크기를 생각할 때, 지금 내가 용서해야 할 사람은 누구인가요?\n3. 오늘 하루 ''작은 자'' 한 사람을 귀하게 여기는 구체적인 실천은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-26', E'예루살렘을 향한 여정 (마태복음 19장)', E'마태복음 19장', E'예수님께서 갈릴리를 떠나 예루살렘을 향해 가시는 여정이 계속됩니다. 요단 강 건너 유대 지경에 이르신 예수님을 큰 무리가 따르며, 예수님은 그들의 병을 고쳐주십니다. 그런데 바리새인들이 나타나 예수님을 시험하려고 이혼에 관한 논쟁적인 질문을 던집니다. 당시 유대 사회에서는 이혼이 너무 쉽게 행해지고 있었고, 이혼의 정당한 사유가 무엇인지를 두고 랍비들 사이에서도 의견이 분분했습니다.\n\n예수님은 그들의 질문에 창조의 원리로 답하십니다. 하나님께서 처음부터 사람을 남자와 여자로 지으시고, 둘이 한 몸이 되도록 하셨다는 것입니다. 모세가 이혼 증서를 허락한 것은 사람들의 마음이 완악하기 때문이었을 뿐, 본래 하나님의 뜻은 그렇지 않았다고 분명히 하십니다. 결혼의 신성함과 영원한 언약으로서의 본질을 회복시키신 것입니다.\n\n이어서 사람들이 어린아이들을 데리고 와서 예수님의 축복을 구합니다. 제자들은 이를 막으려 하지만, 예수님은 "천국이 이런 사람의 것이니라"고 말씀하시며 어린아이들을 환영하십니다. 어린아이의 순수한 믿음과 겸손한 자세가 천국 백성의 모습임을 가르치신 것입니다.\n\n그런데 한 부유한 청년이 와서 영생을 얻는 방법을 묻습니다. 그는 계명을 다 지켰다고 자부하지만, 예수님은 그에게 소유를 팔아 가난한 자들에게 주고 따르라고 하십니다. 재물이 많았던 청년은 근심하며 떠나갑니다. 예수님은 이를 통해 부자가 천국에 들어가기가 낙타가 바늘귀로 들어가는 것보다 어렵다고 말씀하십니다. 그러나 "사람으로는 할 수 없으나 하나님으로서는 다 하실 수 있느니라"는 은혜의 말씀도 덧붙이십니다.\n\n이 장면들은 모두 천국에 들어가는 것이 우리의 노력이나 자격으로 되는 것이 아님을 보여줍니다. 어린아이처럼 겸손히 받아들이는 믿음, 그리고 모든 것보다 예수님을 따르는 것을 우선시하는 헌신이 필요합니다. 베드로가 "우리가 모든 것을 버리고 주를 따랐사온대"라고 말했을 때, 예수님은 그들에게 영광스러운 약속을 주십니다. 하지만 동시에 "먼저 된 자로서 나중 되고 나중 된 자로서 먼저 될 자가 많으니라"고 경고하시며, 겸손의 자세를 잃지 말 것을 당부하십니다.', E'오늘의 핵심\n예수님은 결혼의 신성함을 회복시키시고, 어린아이같은 겸손한 믿음과 모든 것을 버리고 따르는 헌신이 천국 백성의 참된 모습임을 가르치십니다.\n\n묵상 질문\n1. 나는 하나님이 짝지어 주신 관계들을 어떻게 소중히 여기고 있나요?\n2. 부유한 청년처럼 나를 붙잡고 있어 예수님을 온전히 따르지 못하게 하는 것은 무엇인가요?\n3. 어린아이처럼 겸손한 마음으로 천국을 받아들이고 있나요, 아니면 무언가를 이루어야 한다는 생각에 사로잡혀 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-27', E'예루살렘을 향한 여정 (마태복음 20장)', E'마태복음 20장', E'마태복음 20장은 천국의 역설적 가치관을 세 가지 이야기로 보여줍니다. 먼저 포도원 품꾼의 비유는 우리가 당연하게 여기는 공평함의 개념을 뒤흔듭니다. 이른 아침부터 일한 사람과 저녁 늦게 와서 한 시간만 일한 사람이 똑같은 품삯을 받습니다. 먼저 온 사람들의 원망은 충분히 이해할 만합니다. 그러나 주인의 대답은 하나님 나라의 은혜가 우리의 계산법과 다르다는 것을 보여줍니다. "내가 선하므로 네가 악하게 보느냐"는 물음은 하나님의 은혜가 인간의 공로가 아닌 하나님의 선하심에 기초한다는 진리를 드러냅니다.\n\n이어서 예수님은 세 번째로 자신의 죽음을 예고하십니다. 예루살렘으로 올라가는 길에서 조롱과 채찍질과 십자가가 기다리고 있음을 아시면서도 그 길을 가십니다. 그런데 바로 이 엄숙한 순간에 세베대의 아들들의 어머니가 와서 자기 아들들을 좌우편에 앉혀 달라고 청합니다. 십자가를 앞둔 예수님과 권력을 꿈꾸는 제자들의 대조가 극명합니다. 예수님은 그들에게 "내가 마시려는 잔을 너희가 마실 수 있느냐"고 물으십니다. 영광의 자리는 고난의 잔을 마시는 것과 분리될 수 없음을 가르치신 것입니다.\n\n다른 열 제자가 이 일로 분개했을 때, 예수님은 섬김의 리더십을 가르치십니다. 세상의 통치자들은 권력을 휘두르지만, 하나님 나라에서는 섬기는 자가 큰 자라는 것입니다. 그리고 예수님 자신이 바로 그 모범이셨습니다. "인자가 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라." 이 선언은 곧 예루살렘에서 실현될 것이었습니다.\n\n마지막으로 여리고의 두 맹인이 예수님을 부릅니다. 무리가 잠잠하라고 꾸짖었지만 그들은 더욱 크게 외쳤습니다. 예수님은 걸음을 멈추시고 그들의 필요를 물으셨습니다. 권력을 구했던 제자들과 달리, 이들은 단지 눈을 뜨기를 원했습니다. 예수님은 불쌍히 여기사 그들의 눈을 만지셨고, 고침 받은 그들은 예수님을 따랐습니다. 참된 제자도는 높은 자리를 구하는 것이 아니라, 예수님의 긍휼을 경험하고 그분을 따르는 것임을 보여줍니다.', E'오늘의 핵심\n하나님 나라는 먼저 된 자가 나중 되고 섬기는 자가 큰 자가 되는 역설적 질서로 운영되며, 이는 자기 목숨을 대속물로 주신 예수님을 통해 완성됩니다.\n\n묵상 질문\n1. 포도원 품꾼 비유에서 주인의 선함이 불공평하게 느껴진 적이 있나요? 하나님의 은혜가 내 기준과 다를 때 어떻게 반응합니까?\n2. 높은 자리보다 섬기는 자리를 택하신 예수님의 모습이 오늘 내 삶에 어떤 도전을 주나요?\n3. 여리고의 맹인들처럼 간절히 주님께 구하고 싶은 것은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-28', E'예루살렘 입성과 예수의 설득 (마태복음 21장)', E'마태복음 21장', E'예루살렘으로 향하시는 예수님의 모습은 구약의 예언을 성취하는 동시에 우리의 기대를 뒤집습니다. 나귀 새끼를 타고 입성하시는 왕의 모습은 스가랴가 예언한 대로 "겸손하여 나귀, 곧 멍에 메는 짐승의 새끼를 탔도다"(21:5)라는 말씀을 그대로 이루어냅니다. 백성들은 겉옷을 길에 펴고 나뭇가지를 흔들며 "호산나 다윗의 자손이여!"라고 환호했지만, 그들이 기대한 정치적 메시아와 예수님이 보여주신 겸손한 왕의 모습 사이에는 큰 간극이 있었습니다.\n\n성전에 들어가신 예수님의 첫 행동은 매매하는 자들을 내쫓는 것이었습니다. 기도하는 집이어야 할 성전이 강도의 소굴로 변질된 현실은 당시 종교 지도자들의 영적 타락을 고스란히 드러내 줍니다. 그런 가운데서도 예수님은 맹인과 저는 자들을 고치시며 성전의 참된 목적, 곧 하나님의 치유와 회복이 일어나는 장소임을 몸소 보여주십니다.\n\n종교 지도자들과의 권위 논쟁은 그들의 위선을 더욱 선명하게 드러냅니다. 세례 요한의 권위를 인정하지 못하는 그들에게 예수님은 두 아들의 비유를 통해 말과 행동이 다른 신앙의 민낯을 보여주십니다. "가겠나이다"라고 대답했으나 가지 않은 맏아들은 바로 입술로는 하나님을 섬긴다 하면서 실제로는 순종하지 않는 그들의 모습이었습니다.\n\n포도원 농부의 비유는 더욱 날카롭게 그들의 죄악을 지적합니다. 하나님께서 맡기신 포도원을 자기 소유인 양 착각하고, 주인이 보낸 종들을 해치며, 급기야 아들까지 죽이는 농부들의 모습은 선지자들을 박해하고 이제 하나님의 아들까지 거부하는 이스라엘의 역사를 압축적으로 보여줍니다.\n\n무화과나무를 저주하신 사건도 같은 맥락에서 이해됩니다. 잎만 무성하고 열매가 없는 나무는 겉모습만 화려하고 실상은 열매 맺지 못하는 당시 종교의 현주소를 상징합니다. 예수님은 이를 통해 참된 믿음과 진실한 순종만이 하나님 앞에서 가치 있음을 가르쳐 주십니다.\n\n오늘 우리도 묻습니다. 나는 어떤 모습으로 주님을 맞이하고 있는가? 호산나를 외치는 입술만큼 삶에서도 겸손한 왕이신 예수님께 순종하고 있는가? 혹시 "가겠나이다"라고 대답만 하고 실제로는 움직이지 않는 신앙생활을 하고 있지는 않은가? 주님은 오늘도 우리에게 진실한 믿음과 행동이 일치하는 삶을 요구하십니다.', E'오늘의 핵심\n겸손한 왕으로 오신 예수님은 성전을 정결케 하시고, 두 아들과 포도원 농부의 비유를 통해 말과 행동이 일치하지 않는 종교 지도자들의 위선을 드러내십니다.\n\n묵상 질문\n1. 나는 호산나를 외치는 입술만큼 실제 삶에서도 예수님께 순종하고 있나요?\n2. 하나님께서 내게 맡기신 삶의 자리를 나의 소유인 양 움켜쥐고 있지는 않나요?\n3. 잎만 무성한 무화과나무가 아닌, 진실한 열매를 맺는 신앙생활을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-29', E'예루살렘 입성과 예수의 설득 (마태복음 22장)', E'마태복음 22장', E'예수님께서 들려주신 혼인 잔치 비유는 하나님 나라의 초청이 얼마나 은혜로운 것인지, 그리고 그 초청을 거절하는 것이 얼마나 어리석은 일인지를 보여줍니다. 임금이 아들의 혼인 잔치를 준비하고 사람들을 초청했으나, 청함을 받은 이들은 각자의 일상에 매여 그 귀한 초대를 외면합니다. 밭으로, 사업으로 가버린 그들의 모습은 하나님보다 세상일을 우선시하는 우리의 모습을 비춥니다. 더 나아가 종들을 해친 이들의 행위는 하나님의 메신저들을 거부하고 핍박했던 이스라엘의 역사를 압축적으로 보여줍니다.\n\n그러나 하나님의 초청은 멈추지 않습니다. 네거리로 나가 만나는 대로 사람들을 불러오는 장면은 복음이 유대인을 넘어 이방인에게까지 열렸음을 의미합니다. 다만 예복을 입지 않은 사람이 쫓겨나는 것은, 은혜로 주어진 구원이라 할지라도 그에 합당한 삶의 변화가 따라야 함을 가르쳐줍니다.\n\n이어지는 세 가지 논쟁은 예수님의 지혜와 권위를 더욱 선명하게 드러냅니다. 바리새인들과 헤롯당원들이 세금 문제로 함정을 파놓았을 때, "가이사의 것은 가이사에게, 하나님의 것은 하나님께"라는 예수님의 대답은 그들을 놀라게 했습니다. 이 말씀은 단순히 정교분리의 원칙을 넘어, 우리가 하나님의 형상대로 지음받은 존재로서 온전히 하나님께 속해야 함을 일깨워줍니다.\n\n사두개인들의 부활 논쟁에서도 예수님께서는 그들의 편협한 사고를 지적하십니다. "하나님은 죽은 자의 하나님이 아니요 살아 있는 자의 하나님"이라는 선언은 부활이 단지 미래의 사건이 아니라 지금도 살아계신 하나님과의 관계 속에서 경험되는 실재임을 보여줍니다.\n\n마침내 율법사가 가장 큰 계명을 묻자, 예수님께서는 하나님 사랑과 이웃 사랑으로 요약하십니다. 이 두 계명이 "온 율법과 선지자의 강령"이라는 말씀은, 수많은 규정과 전통에 매몰되어 있던 종교 지도자들에게 신앙의 본질을 일깨워주는 것이었습니다. 그리고 다윗이 메시아를 "주"라 부른 시편을 인용하시며, 예수님께서는 단순한 정치적 메시아가 아닌 하나님의 아들이심을 암시하십니다.', E'오늘의 핵심\n예수님께서는 혼인 잔치 비유와 세 가지 논쟁을 통해 하나님 나라의 초청에 합당하게 응답하는 삶과 참된 신앙의 본질이 무엇인지 가르쳐주십니다.\n\n묵상 질문\n1. 나는 하나님의 초청보다 일상의 바쁨을 핑계로 삼고 있지는 않나요?\n2. 하나님의 형상으로 지음받은 내가 온전히 하나님께 속한 삶을 살고 있나요?\n3. 하나님 사랑과 이웃 사랑의 계명을 실제 삶에서 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-30', E'예루살렘 입성과 예수의 설득 (마태복음 23장)', E'마태복음 23장', E'예수님께서 무리와 제자들에게 마지막으로 하신 공개 설교는 당시 종교 지도자들의 위선을 정면으로 다룹니다. "그들이 말하는 바는 행하고 지키되 그들이 하는 행위는 본받지 말라"는 말씀이 전체 메시지의 핵심을 담고 있습니다. 그들은 모세의 자리에 앉아 율법을 가르치면서도 정작 자신들은 그 율법의 정신을 따르지 않았던 것입니다.\n\n예수님은 일곱 번의 "화 있을진저"를 선포하시며 그들의 외식을 낱낱이 드러내십니다. 십일조는 철저히 드리면서 정의와 긍휼과 믿음은 버린 모습, 잔과 대접의 겉은 깨끗이 하면서 안은 탐욕으로 가득 채운 모습이 그들의 실상이었습니다. 특히 "회칠한 무덤"의 비유는 충격적입니다. 겉으로는 아름답게 보이지만 속은 죽음으로 가득한 무덤처럼, 그들의 신앙도 겉모습만 화려할 뿐이었습니다.\n\n그러나 이 엄중한 책망 가운데서도 예수님의 마음은 분명히 드러납니다. "암탉이 그 새끼를 날개 아래에 모음 같이 내가 네 자녀를 모으려 한 일이 몇 번이더냐"(마 23:37)라는 탄식에는 끝까지 그들을 구원하고자 하시는 간절함이 담겨 있습니다. 예수님의 책망은 정죄가 아닌 회개로의 초청이었던 것입니다.\n\n웨슬리가 강조했듯이, 참된 신앙은 내적 거룩함과 외적 행위가 일치하는 데 있습니다. 하나님께서는 우리의 겉모습이 아니라 중심을 보십니다. 오늘날 우리도 종교적 형식에만 매달리며 정작 하나님과의 관계는 소홀히 하고 있지는 않은지 돌아봐야 합니다. 신앙의 본질은 사람들에게 보이는 것이 아니라 하나님 앞에서의 진실함입니다. 예수님께서 가르치신 대로 "너희 중에 큰 자는 너희를 섬기는 자가 되어야" 합니다. 이것이 하나님 나라의 원리이며, 참된 제자도의 길입니다.', E'오늘의 핵심\n예수님은 종교 지도자들의 외식을 일곱 번의 "화 있을진저"로 책망하시면서도, 암탉이 새끼를 품듯 그들을 구원하고자 하시는 간절한 마음을 보여주십니다.\n\n묵상 질문\n1. 나의 신앙생활에서 겉모습과 속마음이 다른 부분은 없나요?\n2. 섬김의 리더십을 실천하기 위해 오늘 내가 할 수 있는 일은 무엇인가요?\n3. 예수님의 책망을 통해 회개하고 돌이켜야 할 영역이 있다면 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-01', E'용서를 향한 예수의 열정 (마태복음 26장)', E'마태복음 26장', E'유월절을 앞두고 예수님께서는 제자들에게 자신이 십자가에 못 박히실 것을 예고하십니다. 때마침 베다니에서 한 여인이 값비싼 향유를 예수님께 부어드리는 일이 일어납니다. 제자들은 그 낭비를 책망했지만, 예수님은 오히려 그 여인의 행위가 당신의 장례를 준비하는 아름다운 일이라고 칭찬하십니다. 이 사건은 예수님의 죽음이 임박했음을 보여주는 동시에, 진정한 헌신이 무엇인지를 가르쳐줍니다.\n\n유월절 만찬 자리에서 예수님은 제자 중 한 사람이 자신을 배반할 것을 말씀하시고, 떡과 포도주를 나누시며 새 언약을 선포하십니다. 이 거룩한 순간은 구약의 유월절이 예수님의 십자가 사건으로 완성되는 구속사적 전환점이 됩니다. 그러나 제자들은 여전히 이 일의 의미를 깨닫지 못한 채, 자신들은 결코 주님을 버리지 않겠다고 장담합니다.\n\n겟세마네 동산에서의 기도는 예수님의 인성과 신성이 가장 극명하게 드러나는 장면입니다. "이 잔을 내게서 지나가게 하옵소서"라는 간절한 기도 속에서도 "아버지의 원대로 하옵소서"라는 순종의 고백이 이어집니다. 한편 제자들은 육신의 연약함을 이기지 못하고 잠들어 버립니다. 마침내 유다가 무리를 이끌고 와서 입맞춤으로 예수님을 넘겨주고, 한 제자가 칼을 빼어 저항하려 하지만 예수님은 이를 제지하십니다. 하나님의 구원 계획은 인간의 폭력이 아닌 어린 양의 희생을 통해 성취되어야 했기 때문입니다.', E'오늘의 핵심\n예수님은 십자가의 길을 자원하여 선택하시며, 제자들의 연약함 속에서도 구원의 계획을 신실하게 이루어 가십니다.\n\n묵상 질문\n1. 향유를 부은 여인처럼 내가 예수님께 드릴 수 있는 가장 귀한 것은 무엇일까요?\n2. 겟세마네의 기도에서 보여주신 예수님의 순종이 나의 기도 생활에 어떤 도전을 주나요?\n3. 베드로처럼 확신에 찬 고백 뒤에 넘어질 수 있는 나의 연약함을 어떻게 인정하고 의지할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-03', E'용서를 향한 예수의 열정 (마태복음 27장)', E'마태복음 27장', E'새벽이 밝아오자 종교 지도자들은 예수님을 로마 총독 빌라도에게 넘겨줍니다. 그때 예수님을 팔았던 유다는 자신의 행위를 뉘우치며 은 삼십 개를 되돌려주려 하지만, 대제사장들은 차갑게 외면합니다. 절망한 유다는 스스로 목숨을 끊고, 그 돈은 나그네의 묘지를 사는 데 쓰여 ''피밭''이라는 이름을 남깁니다.\n\n빌라도 앞에 서신 예수님의 재판은 공의가 아닌 정치적 타협의 장이 됩니다. 빌라도는 예수님의 무죄함을 알면서도 군중의 압력에 굴복합니다. 명절 특사로 풀려날 수 있었던 자리에 흉악범 바라바가 선택되고, 의로우신 분은 십자가형을 선고받습니다. "그 피를 우리와 우리 자손에게 돌릴지어다"라는 군중의 외침은 그들이 얼마나 맹목적인 증오에 사로잡혀 있었는지를 보여줍니다.\n\n골고다 언덕으로 향하는 길, 로마 군병들의 조롱과 채찍질 속에서도 예수님은 묵묵히 십자가를 지셨습니다. 가시 면류관과 홍포는 왕을 흉내 낸 잔인한 희롱이었지만, 역설적으로 그분이 진정한 왕이심을 드러내는 표징이 됩니다. 십자가 위에서 "나의 하나님, 나의 하나님, 어찌하여 나를 버리셨나이까"라고 부르짖으신 예수님의 절규는 인류의 모든 죄를 대신 짊어지신 고통의 깊이를 보여줍니다.\n\n예수님께서 숨을 거두시는 순간, 성소의 휘장이 위에서 아래로 찢어집니다. 이는 하나님과 인간 사이의 막힌 담이 무너지고 새로운 은혜의 시대가 열렸음을 선포합니다. 지진과 부활한 성도들의 모습은 죽음의 권세가 깨어졌음을 증거합니다. 이 모든 일을 목격한 로마 백부장조차 "이는 진실로 하나님의 아들이었도다"라고 고백하게 됩니다. 인간의 악의와 불의가 극에 달했던 그 날, 하나님의 구원 계획은 오히려 완성되고 있었습니다.', E'오늘의 핵심\n인간의 불의와 증오가 절정에 이른 십자가에서, 하나님께서는 오히려 죄인을 위한 구원의 길을 여시고 새 언약의 시대를 시작하셨습니다.\n\n묵상 질문\n1. 빌라도처럼 진실을 알면서도 타협하는 내 모습은 없나요?\n2. 예수님의 십자가 고난이 나에게는 어떤 의미로 다가오나요?\n3. 찢어진 성소 휘장처럼 내 삶에서 하나님과의 막힌 담은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-04', E'용서를 향한 예수의 열정 (마태복음 28장)', E'마태복음 28장', E'안식일이 지나고 새벽이 밝아올 무렵, 막달라 마리아와 다른 마리아가 무덤을 찾아갔을 때 놀라운 일이 일어났습니다. 큰 지진과 함께 주의 천사가 하늘로부터 내려와 무덤을 막고 있던 돌을 굴려내고 그 위에 앉았습니다. 번개같이 빛나는 천사의 모습에 로마 병사들은 죽은 사람처럼 쓰러졌지만, 천사는 여인들에게 "무서워하지 말라"고 말하며 십자가에 못 박히신 예수님께서 말씀하신 대로 부활하셨음을 선포합니다. 빈 무덤은 죽음을 이기신 예수님의 승리를 증명하는 확실한 증거였습니다.\n\n무서움과 큰 기쁨이 교차하는 가운데 여인들이 제자들에게 이 소식을 전하려고 달려가는 길에서 부활하신 예수님을 직접 만나게 됩니다. 주님께서는 그들에게 "평안하냐"라고 인사하시며, 제자들에게 갈릴리로 가라는 메시지를 전하라고 하십니다. 한편 대제사장들은 경비병들에게 돈을 주어 제자들이 시신을 훔쳐갔다는 거짓말을 퍼뜨리게 했지만, 부활의 진실은 결코 가려질 수 없었습니다.\n\n갈릴리의 한 산에서 열한 제자들과 만나신 예수님께서는 하늘과 땅의 모든 권세가 자신에게 주어졌음을 선포하시며, 제자들에게 모든 민족을 제자로 삼으라는 대사명을 주십니다. 아버지와 아들과 성령의 이름으로 세례를 베풀고, 예수님께서 가르치신 모든 것을 가르쳐 지키게 하라는 이 명령은 오늘날 교회가 존재하는 이유이자 목적입니다. 그리고 "내가 세상 끝날까지 너희와 항상 함께 있으리라"는 약속으로 복음서를 마무리하십니다. 이 약속은 부활하신 주님께서 성령으로 우리와 함께하시며, 복음 전파의 사명을 감당할 수 있도록 능력을 주신다는 확증입니다.', E'오늘의 핵심\n죽음을 이기고 부활하신 예수님께서는 모든 권세를 가지고 제자들에게 온 세상에 복음을 전하라는 사명을 주시며, 세상 끝날까지 함께하시겠다고 약속하십니다.\n\n묵상 질문\n1. 부활의 첫 증인이 된 여인들의 두려움과 기쁨을 통해 하나님은 무엇을 가르치시나요?\n2. 의심하는 제자들에게도 사명을 주신 예수님의 은혜가 나에게 어떤 위로가 되나요?\n3. "세상 끝날까지 함께 있으리라"는 약속이 오늘 나의 삶에서 어떻게 경험되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-05', E'예수의 예루살렘 입성과 대결 (마가복음 1장)', E'마가복음 1장', E'마가복음은 시작부터 강렬합니다. 이사야의 예언이 성취되며 세례 요한이 광야에 나타나 회개의 세례를 전파합니다. 낙타털 옷을 입고 메뚜기와 석청을 먹으며 사는 그의 모습은 구약의 선지자들을 연상시키지만, 그가 전하는 메시지는 새로운 시대의 도래를 알립니다. "나보다 능력 많으신 이가 내 뒤에 오시나니 나는 굽혀 그의 신발끈을 풀기도 감당하지 못하겠노라"(막 1:7). 요한은 자신의 역할을 정확히 알고 있었습니다. 물로 베푸는 회개의 세례를 넘어 성령으로 세례를 베푸실 분을 준비하는 것이었습니다.\n\n예수님이 요단강에서 세례를 받으실 때 일어난 일은 하나님 나라 역사의 결정적 전환점이었습니다. 하늘이 갈라지고 성령이 비둘기같이 내려오시며 "너는 내 사랑하는 아들이라"는 하늘의 선언이 울려 퍼집니다. 이는 단순한 인정이 아니라 메시아적 사명의 공식적 시작을 알리는 것이었습니다. 곧이어 성령은 예수님을 광야로 이끄셨고, 40일간의 시험을 통해 메시아로서의 길을 확증하게 하셨습니다.\n\n갈릴리에서 시작된 예수님의 공생애는 "때가 찼고 하나님의 나라가 가까이 왔으니 회개하고 복음을 믿으라"는 선포로 요약됩니다. 이 선포는 단지 말씀으로만 이루어진 것이 아니었습니다. 어부들을 부르시고, 회당에서 권위 있게 가르치시며, 귀신을 쫓아내시고, 병자를 고치시는 일들을 통해 하나님 나라의 능력이 구체적으로 나타났습니다. 사람들이 놀란 것은 그분의 가르침이 "권위 있는 자와 같고 서기관들과 같지 아니함"이었습니다. 귀신조차 예수님을 "하나님의 거룩한 자"로 알아보았습니다.\n\n특히 주목할 것은 예수님의 일상입니다. 밤늦도록 병자들을 고치신 후에도 "새벽 아직도 밝기 전에" 한적한 곳으로 가서 기도하셨습니다. 그리고 제자들이 찾아와 "모든 사람이 주를 찾나이다"라고 할 때, 예수님은 "다른 가까운 마을들로 가자"고 하십니다. 인기에 안주하지 않고 더 많은 영혼에게 복음을 전하려는 분명한 사명 의식이 있었습니다. 나병환자를 고치신 후 비밀을 지키라고 당부하신 것도 단순히 치유자가 아닌 복음 전파자로서의 사명을 잃지 않기 위함이었습니다. 마가복음 1장은 이렇게 권위와 능력, 그리고 분명한 사명을 가지신 하나님의 아들 예수 그리스도를 우리에게 소개합니다.', E'오늘의 핵심\n예수님은 하늘의 인정을 받은 하나님의 아들로서 권위 있는 가르침과 능력의 사역으로 하나님 나라의 도래를 선포하시며, 철저한 기도와 분명한 사명 의식으로 복음을 전파하십니다.\n\n묵상 질문\n1. 예수님의 권위가 서기관들과 다른 점은 무엇이며, 나는 어떤 권위로 살아가고 있나요?\n2. 예수님처럼 새벽에 기도하며 하나님과의 교제를 우선순위에 두고 있나요?\n3. "때가 찼고 하나님 나라가 가까이 왔다"는 선포가 내 삶에서는 어떻게 구현되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-06', E'예수의 예루살렘 입성과 대결 (마가복음 2장)', E'마가복음 2장', E'가버나움의 한 집에 예수님이 계시다는 소식이 전해지자 사람들이 문전성시를 이룹니다. 그런데 네 사람이 중풍병자 친구를 데려왔다가 인파에 막히자 놀라운 일을 벌입니다. 지붕을 뜯어 구멍을 내고 친구를 달아 내린 것입니다. 그들의 간절함과 믿음을 보신 예수님은 중풍병자에게 "네 죄 사함을 받았느니라"고 선언하십니다. 병 고침을 기대했는데 죄 사함을 선포하신 것입니다. 이는 육신의 치유보다 영혼의 회복이 더 근본적임을 보여주는 동시에, 예수님이 죄를 사하는 신적 권위를 가지신 분임을 드러내는 선언이었습니다. \n\n서기관들이 마음속으로 "신성 모독"이라고 반발하자, 예수님은 그들의 생각을 꿰뚫어 보시고 중풍병자를 즉시 일으켜 세우십니다. 죄 사함의 권세를 가시적으로 입증하신 것입니다. 이어서 세리 레위를 제자로 부르시고 죄인들과 함께 식탁 교제를 나누시는 모습은 당시 종교 지도자들에게는 충격적이었습니다. 그러나 예수님은 분명히 말씀하십니다. "나는 의인을 부르러 온 것이 아니요 죄인을 부르러 왔노라." 의사가 병든 자에게 필요하듯, 구원자는 죄인에게 필요하다는 은혜의 선언입니다.\n\n혼인 잔치의 비유와 새 포도주 비유는 예수님이 가져오신 하나님 나라의 새로운 차원을 보여줍니다. 율법의 형식에 갇힌 낡은 틀로는 복음의 생명력을 담아낼 수 없습니다. 안식일에 밀 이삭을 자른 제자들을 비난하는 바리새인들에게 예수님은 안식일의 참 의미를 일깨우십니다. "안식일이 사람을 위하여 있는 것이요 사람이 안식일을 위하여 있는 것이 아니니." 율법의 정신은 생명을 살리는 것이지 속박하는 것이 아닙니다. 인자이신 예수님은 안식일의 주인으로서 참된 안식, 곧 죄로부터의 해방과 하나님과의 화목을 주시는 분이십니다.', E'오늘의 핵심\n예수님은 죄를 사하는 권세와 안식일의 주인 되심을 선포하시며, 율법의 형식이 아닌 생명을 살리는 은혜의 복음을 보여주십니다.\n\n묵상 질문\n1. 지붕을 뜯을 정도로 간절히 예수님께 나아가야 할 내 삶의 문제는 무엇인가요?\n2. 내가 붙잡고 있는 종교적 형식이 오히려 은혜를 가로막고 있지는 않나요?\n3. 예수님이 죄인을 부르러 오셨다는 말씀이 나에게는 어떤 위로와 도전이 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-07', E'열두 제자 선택', E'마가복음 3장', E'예수님께서는 공생애를 시작하시면서 가장 먼저 하신 일이 있습니다. 바로 함께할 사람을 부르신 것입니다. 갈릴리 바닷가의 평범한 어부 시몬과 안드레, 야고보와 요한, 그리고 세관에 앉아 있던 레위까지 세상의 기준으로는 특별할 것 없는 사람들이었습니다. 그런데 예수님은 바로 그들을 택하셔서 열두 제자로 세우시고, 가르치고 고치는 사역을 함께 감당하게 하셨습니다.\n\n주목할 점은 예수님께서 혼자서도 충분히 모든 일을 하실 수 있었다는 것입니다. 회당에서 귀신을 내쫓으시고, 각종 병을 고치시며, 큰 무리에게 가르침을 주시는 분이셨습니다. 그럼에도 예수님은 사람을 부르셨습니다. 하나님의 일은 처음부터 ''함께''의 방식으로 설계되었기 때문입니다. 완벽해서 불린 것이 아니라, 부름받아 함께 걸으며 변화되는 것이 제자의 길입니다.\n\n또한 예수님의 사역을 비방하는 자들 앞에서도 예수님은 가르치기를 멈추지 않으셨습니다. "새 포도주는 새 부대에 넣느니라"는 말씀처럼, 예수님이 가져오신 복음은 기존의 틀에 억지로 끼워 맞출 수 없는 전혀 새로운 것이었습니다. 낡은 관습과 편견에 갇혀 있던 사람들에게 예수님은 새로운 시선으로 하나님 나라를 바라보라고 초청하신 것입니다.\n\n지금 내가 서 있는 자리가 어디든 직장이든, 학교든, 아직 방향을 찾는 중이든 예수님은 그 자리에서 나를 부르고 계십니다. 준비가 덜 된 것 같아도, 자격이 부족한 것 같아도 괜찮습니다. 어부의 그물가에서, 세관의 책상 앞에서 부르셨던 그 예수님이 오늘 나에게도 "나를 따르라"고 말씀하고 계십니다.\n\n오늘 나를 묶고 있는 ''낡은 부대'' 자격지심, 두려움, 익숙한 안전지대는 무엇인지 돌아보고, 예수님의 부르심 앞에 새롭게 응답하는 하루가 되기를 소망합니다.', E'오늘의 핵심\n예수님은 공생애를 시작하시면서 열두 제자를 선택하여 부르시고 그들을 가르치시며 함께 하나님 나라의 일들을 행하십니다.\n\n묵상 질문\n예수님이 제자들을 부르실 때 어떤 마음과 목적으로 그들을 선택하셨을까요?\n평신도인 내가 예수님의 제자로서 어떤 역할을 감당할 수 있을까요?\n예수님을 따르기 위해 내가 지금 내려놓아야 할 것은 무엇인지 기도해 보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-08', E'예수의 이적과 가르침 (마가복음 4장)', E'마가복음 4장', E'예수님께서는 바닷가에서 큰 무리를 가르치셨습니다. 사람들이 너무 많아 배에 올라 앉으시고 해변에 모인 무리에게 비유로 말씀하셨는데, 그 중심에는 씨 뿌리는 자의 비유가 있었습니다. 같은 씨앗이 떨어진 땅의 상태에 따라 전혀 다른 결과를 맺는다는 이 비유는, 하나님의 말씀을 듣는 우리 마음의 상태가 얼마나 중요한지를 보여줍니다.\n\n길가와 같이 굳은 마음에는 말씀이 뿌리를 내리기도 전에 사탄이 빼앗아 갑니다. 돌밭 같은 마음은 처음에는 기쁨으로 받지만 시련이 오면 쉽게 포기합니다. 가시떨기 같은 마음은 세상의 염려와 재물의 유혹에 말씀이 막혀 열매를 맺지 못합니다. 그러나 좋은 땅과 같은 마음은 말씀을 듣고 받아 삼십 배, 육십 배, 백 배의 결실을 맺습니다. 예수님은 "들을 귀 있는 자는 들으라"(막 4:9)고 거듭 강조하시며, 듣는 것의 중요성을 일깨우십니다.\n\n이어지는 비유들도 하나님 나라의 신비를 드러냅니다. 등불은 감추려고 켜는 것이 아니라 비추려고 켜는 것처럼, 하나님의 진리는 결국 드러나게 됩니다. 씨앗이 땅에서 저절로 자라는 것처럼 하나님 나라는 우리가 이해할 수 없는 방식으로 성장하며, 작은 겨자씨가 큰 나무가 되듯 하나님 나라는 미약한 시작에서 놀라운 확장을 이룹니다.\n\n그날 저녁, 예수님은 하루 종일 가르치신 후 피곤하셨을 것입니다. 제자들과 함께 배를 타고 건너편으로 가시던 중, 고물에서 베개를 베고 깊이 잠드셨습니다. 그때 큰 광풍이 일어나 배에 물이 가득 차게 되자 제자들은 공포에 사로잡혔습니다. 예수님을 깨운 제자들에게 예수님은 먼저 바람과 바다를 꾸짖어 잠잠케 하신 후, 그들의 믿음 없음을 지적하셨습니다. 이 사건은 말씀의 권위를 가르치신 분이 곧 창조주 하나님의 권위를 가지신 분임을 보여줍니다. 제자들의 "그가 누구이기에"라는 질문은 오늘 우리에게도 동일하게 던져집니다.', E'오늘의 핵심\n예수님은 비유를 통해 하나님 나라의 비밀을 가르치시고, 자연을 다스리는 권능으로 자신이 누구인지를 계시하셨습니다.\n\n묵상 질문\n1. 내 마음은 어떤 밭과 같은가요? 말씀의 씨앗이 열매 맺지 못하게 하는 방해물은 무엇인가요?\n2. 인생의 풍랑 속에서도 평안히 주무실 수 있는 예수님을 신뢰하고 있나요?\n3. "그가 누구이기에"라는 제자들의 질문에 나는 어떤 고백으로 응답하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-10', E'예수의 이적과 가르침 (마가복음 5장)', E'마가복음 5장', E'바다 건너편 거라사인의 지방에 도착하신 예수님을 맞이한 것은 더러운 귀신 들린 한 사람이었습니다. 그는 무덤 사이에서 살며, 쇠사슬도 끊어버릴 만큼 강력한 힘에 사로잡혀 밤낮으로 소리 지르며 돌로 자기 몸을 해치고 있었습니다. 사람들이 포기한 이 한 영혼을 위해 예수님은 풍랑을 뚫고 오셨습니다. 귀신들이 돼지 떼로 들어가 이천 마리가 몰사하는 엄청난 경제적 손실이 발생했지만, 예수님께는 한 사람의 회복이 그 무엇보다 소중했습니다. 정신이 온전해진 그가 예수님과 함께 있기를 간청했을 때, 주님은 오히려 그를 가족에게 돌려보내며 하나님의 큰 일을 전하라고 하십니다. 구원받은 자의 첫 사명은 가장 가까운 곳에서 시작됨을 보여주십니다.\n\n다시 바다를 건너오신 예수님께 회당장 야이로가 찾아와 죽어가는 딸을 위해 간절히 구합니다. 그런데 가시는 길에 열두 해 동안 혈루증으로 고통받던 여인이 믿음으로 예수님의 옷자락을 만집니다. 율법상 부정한 자로 여겨져 사람들 틈에 끼일 수도 없었던 그녀는 "내가 그의 옷에만 손을 대어도 구원을 받으리라"는 믿음 하나로 무리 속을 헤치고 나아왔습니다. 예수님은 자기에게서 능력이 나간 것을 아시고 그녀를 찾으셨고, "딸아 네 믿음이 너를 구원하였으니"라며 공개적으로 그녀의 회복을 선포하십니다. \n\n이 지체로 인해 야이로의 딸이 죽었다는 소식이 전해집니다. 절망적인 순간, 예수님은 "두려워하지 말고 믿기만 하라"고 말씀하십니다. 죽음 앞에서도 믿음은 유효합니다. 예수님은 비웃는 무리를 물리치고 "달리다굼"이라는 아람어로 소녀를 일으키십니다. 열두 살 소녀와 열두 해 동안 병든 여인의 이야기가 교차하며, 예수님이 생명의 주관자이심을 선명하게 드러냅니다. 절망의 끝에서도, 모두가 포기한 곳에서도, 예수님은 한 영혼을 찾아오시고 회복시키시는 분이십니다.', E'오늘의 핵심\n예수님은 사회에서 버림받고 소외된 한 영혼을 위해 먼 길을 마다하지 않으시며, 절망적인 상황에서도 믿음으로 나아오는 자를 회복시키시는 생명의 주관자이십니다.\n\n묵상 질문\n1. 거라사 귀신 들린 자처럼 나도 무언가에 묶여 스스로를 해치고 있는 영역은 없나요?\n2. 혈루증 여인처럼 수치와 두려움을 넘어 믿음으로 예수님께 나아가야 할 일은 무엇인가요?\n3. "두려워하지 말고 믿기만 하라"는 예수님의 말씀이 오늘 내 상황에 어떻게 적용되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-11', E'예수의 이적과 가르침 (마가복음 6장)', E'마가복음 6장', E'마가복음 6장은 예수님의 사역이 점차 확장되면서 동시에 거부와 오해, 그리고 놀라운 기적이 교차하는 장면들을 보여줍니다. 고향 나사렛에서 시작되는 이 장은 예수님께서 어떻게 거절당하시면서도 끊임없이 사랑으로 다가가시는지를 생생하게 전해줍니다.\n\n예수님께서 고향 나사렛으로 돌아가셨을 때, 회당에서 가르치시는 그분의 지혜와 권능에 많은 사람들이 놀랐습니다. 그러나 놀라움은 곧 의심과 배척으로 바뀝니다. "이 사람이 마리아의 아들 목수가 아니냐"라는 그들의 반응은 너무나 익숙한 것에 가려져 하나님의 역사를 보지 못하는 인간의 한계를 드러냅니다. 예수님은 고향에서 아무 권능도 행하실 수 없으셨고, 그들의 불신앙을 이상히 여기셨다고 마가는 기록합니다.\n\n이어지는 세례 요한의 죽음은 의로운 자가 겪는 고난의 현실을 보여줍니다. 헤롯의 생일 잔치에서 벌어진 이 비극은 권력의 타락과 진리를 거부하는 인간의 어두운 면을 적나라하게 드러냅니다. 그러나 예수님은 이런 어둠 속에서도 멈추지 않으십니다.\n\n오천 명을 먹이신 기적은 예수님의 긍휼과 능력을 동시에 보여줍니다. 목자 없는 양 같은 무리를 보시고 불쌍히 여기신 예수님은 먼저 말씀으로 그들을 가르치셨고, 이어서 떡 다섯 개와 물고기 두 마리로 그들의 육신의 필요까지 채우셨습니다. 제자들이 "우리가 가서 이백 데나리온의 떡을 사다 먹이리이까"라고 계산적으로 접근할 때, 예수님은 그들에게 있는 작은 것으로 시작하라고 하십니다.\n\n밤 사경에 바다 위를 걸어오신 예수님의 모습은 자연을 다스리시는 창조주의 권능을 보여줍니다. 힘겹게 노를 젓는 제자들을 보시고 그들에게 오신 예수님. "안심하라 내니 두려워하지 말라"는 그분의 음성은 오늘도 인생의 풍랑 속에서 힘겹게 노를 젓는 우리에게 들려옵니다. 마가는 제자들이 떡 떼시던 일을 깨닫지 못하고 마음이 둔하여졌다고 지적하는데, 이는 우리도 일상에서 경험하는 하나님의 은혜를 얼마나 쉽게 잊어버리는지를 돌아보게 합니다.', E'오늘의 핵심\n예수님은 고향에서의 배척과 세례 요한의 죽음이라는 어둠 속에서도 긍휼의 마음으로 무리를 먹이시고, 풍랑 속의 제자들을 찾아오시는 참된 목자이십니다.\n\n묵상 질문\n1. 나는 혹시 너무 익숙한 것들 때문에 하나님의 놀라운 역사를 놓치고 있지는 않나요?\n2. 예수님께서 내 삶의 작은 것들을 사용하실 수 있도록 내어드릴 준비가 되어 있나요?\n3. 인생의 풍랑 속에서 "안심하라 내니"라고 말씀하시는 주님의 음성을 들으며 어떤 평안을 얻게 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-12', E'예수의 이적과 가르침 (마가복음 7장)', E'마가복음 7장', E'바리새인들과 서기관들이 예루살렘에서 와서 예수님의 제자들이 손을 씻지 않고 음식을 먹는 모습을 보고 문제 삼았습니다. 유대인들에게 정결 예식은 단순한 위생 문제가 아니라 장로들의 전통을 지키는 신앙적 행위였습니다. 그런데 예수님은 이사야의 예언을 인용하시며 그들의 위선을 정면으로 지적하십니다. 입술로는 하나님을 공경한다고 하면서도 마음은 멀리 떠나 있었던 것입니다.\n\n예수님은 ''고르반''의 예를 들어 그들의 모순을 드러내십니다. 부모를 봉양해야 할 재물을 하나님께 드렸다고 선언하면 부모 공경의 의무를 면제받는 전통이었습니다. 하나님의 계명인 부모 공경을 사람의 전통으로 무력화시킨 것입니다. 예수님은 밖에서 들어가는 것이 사람을 더럽히는 것이 아니라, 마음에서 나오는 악한 생각과 탐욕, 교만이 사람을 더럽힌다고 선언하셨습니다. 정결의 본질은 외적 의식이 아니라 내면의 거룩함에 있었던 것입니다.\n\n이어서 예수님은 두로 지방으로 가셔서 수로보니게 여인을 만나십니다. 이방인이었던 그녀는 딸의 치유를 간구하며 "상 아래 개들도 아이들이 먹던 부스러기를 먹나이다"라고 겸손히 고백합니다. 형식적 정결함을 자랑하던 바리새인들과는 대조적으로, 그녀는 자신의 낮은 위치를 인정하면서도 예수님의 은혜를 갈망했습니다. 예수님은 그녀의 믿음을 보시고 딸을 고쳐주셨습니다.\n\n데가볼리 지방에서는 귀 먹고 말 더듬는 자를 고치십니다. 예수님은 그를 따로 데리고 가셔서 손가락을 그의 귀에 넣고 침을 뱉어 혀에 손을 대시며 "에바다" 곧 "열리라"고 명하셨습니다. 닫혔던 귀가 열리고 맺혔던 혀가 풀어진 것은 단순한 육체적 치유를 넘어, 하나님의 말씀을 듣고 찬양할 수 있게 된 영적 회복을 상징합니다. 사람들은 "그가 모든 것을 잘하였도다"라고 감탄했습니다. 예수님은 형식적 종교를 넘어 생명을 회복시키는 참된 구원자이셨습니다.', E'오늘의 핵심\n예수님은 외적 형식과 전통에 매인 종교적 위선을 지적하시고, 마음의 정결함과 진실한 믿음이 하나님께 나아가는 참된 길임을 보여주십니다.\n\n묵상 질문\n1. 내가 지키고 있는 신앙의 형식이 오히려 하나님의 뜻을 가로막고 있지는 않나요?\n2. 수로보니게 여인처럼 낮은 자리에서도 예수님의 은혜를 구하는 믿음이 내게 있나요?\n3. 막혔던 귀와 혀가 열린 것처럼, 내 삶에서 열려야 할 영적 감각은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-13', E'예수의 이적과 가르침 (마가복음 8장)', E'마가복음 8장', E'예수님께서 사천 명을 먹이시는 장면은 우리에게 하나님의 긍휼이 무엇인지 보여줍니다. 사흘이나 함께한 무리를 보시며 "내가 무리를 불쌍히 여기노라"고 말씀하시는 예수님의 마음에는 형식이 아닌 진정한 사랑이 있었습니다. 제자들은 광야에서 떡을 구할 길이 없다며 현실적인 한계를 이야기했지만, 예수님은 떡 일곱 개와 작은 생선 두어 마리로 기적을 행하셨습니다. 남은 조각이 일곱 광주리나 되었다는 기록은 하나님의 공급하심이 얼마나 넉넉한지를 증거합니다.\n\n그런데 바리새인들은 이런 놀라운 일을 목격하고도 하늘로부터 오는 표적을 요구했습니다. 예수님은 마음속으로 깊이 탄식하셨습니다. 이미 충분한 표적이 나타났음에도 그들의 눈은 여전히 닫혀 있었기 때문입니다. 예수님은 제자들에게 바리새인들의 누룩과 헤롯의 누룩을 주의하라고 경고하셨습니다. 이 누룩은 하나님의 일하심을 보고도 믿지 않는 불신앙과 교만을 가리킵니다.\n\n제자들조차도 영적으로 둔감했습니다. 떡이 없음을 걱정하는 그들에게 예수님은 오천 명과 사천 명을 먹이신 일을 상기시키셨습니다. 벳새다의 맹인이 단계적으로 시력을 회복하는 장면은 제자들의 영적 상태를 보여주는 듯합니다. 처음에는 나무 같은 것들이 걸어가는 것으로 보이다가, 다시 안수받은 후에야 모든 것을 밝히 보게 되었습니다.\n\n베드로의 고백 "주는 그리스도시니이다"는 영적 눈이 열린 순간을 보여줍니다. 그러나 예수님이 고난과 죽음을 예고하시자 베드로는 즉시 항변했습니다. 그는 메시아를 알아보았지만, 십자가의 길은 이해하지 못했던 것입니다. 예수님은 제자들에게 자기를 부인하고 자기 십자가를 지고 따르라고 말씀하셨습니다. 온 천하를 얻고도 목숨을 잃으면 무엇이 유익하겠느냐는 질문은 우리의 가치관을 뒤흔듭니다. 진정한 생명은 예수님과 복음을 위해 자기를 내려놓을 때 얻어진다는 역설적 진리가 여기에 있습니다.', E'오늘의 핵심\n예수님은 우리의 영적 눈을 열어 메시아를 알아보게 하시지만, 동시에 그 길이 십자가를 통과한다는 것을 가르치십니다. 참된 제자도는 자기를 부인하고 주님을 따르는 것입니다.\n\n묵상 질문\n1. 나는 일상에서 일어나는 하나님의 일하심을 얼마나 민감하게 알아차리고 있나요?\n2. 내가 가진 메시아에 대한 기대와 예수님이 보여주신 십자가의 길 사이에 어떤 간극이 있나요?\n3. 오늘 내가 져야 할 십자가는 무엇이며, 무엇을 위해 나를 내려놓아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-14', E'변화산 사건과 예수의 가르침 (마가복음 9장)', E'마가복음 9장', E'변화산에서 예수님의 영광스러운 모습이 드러났을 때, 하늘에서 들려온 음성은 분명했습니다. "이는 내 사랑하는 아들이니 너희는 그의 말을 들으라." 모세와 엘리야가 함께 나타났지만, 결국 제자들 앞에 남은 것은 오직 예수님뿐이었습니다. 율법과 예언의 완성이신 예수님만이 우리가 들어야 할 유일한 권위임을 보여주는 장면입니다.\n\n산에서 내려오자마자 마주한 현실은 참담했습니다. 제자들은 귀신 들린 아이를 고치지 못해 무력함에 빠져 있었고, 아이의 아버지는 절망적인 상황 속에서 "무엇을 하실 수 있거든 우리를 불쌍히 여기사 도와 주옵소서"라고 간청합니다. 예수님의 대답은 단호했습니다. "할 수 있거든이 무슨 말이냐 믿는 자에게는 능히 하지 못할 일이 없느니라." 이에 아버지는 즉시 "내가 믿나이다 나의 믿음 없는 것을 도와 주소서"라고 외칩니다. 완전하지 못한 믿음이라도 정직하게 고백하며 도움을 구할 때, 주님은 그 연약함을 채워주십니다.\n\n이어서 예수님은 자신의 죽음과 부활을 두 번째로 예고하시지만, 제자들은 여전히 누가 더 큰가를 놓고 다투고 있었습니다. 영광의 자리를 차지하려는 제자들에게 예수님은 어린아이를 안으시며 섬김의 길을 가르치십니다. "누구든지 첫째가 되고자 하면 뭇 사람의 끝이 되며 뭇 사람을 섬기는 자가 되어야 하리라." 하나님 나라의 질서는 세상과 정반대입니다.\n\n마가복음 9장은 제자도의 본질을 날카롭게 보여줍니다. 우리를 따르지 않는다고 배척하려는 배타성, 작은 자를 실족시키는 교만, 죄와 타협하려는 안일함을 모두 경계하십니다. 손과 발과 눈을 찍어버리라는 극단적 표현은 죄에 대한 단호한 결단을 요구하는 것입니다. 제자의 길은 자기 부인과 희생을 통해서만 걸을 수 있는 십자가의 길입니다. 오늘 우리의 신앙이 영광만을 추구하는 것은 아닌지, 섬김보다 섬김받기를 원하는 것은 아닌지 돌아보아야 합니다.', E'오늘의 핵심\n예수님은 영광의 변화산에서 내려와 고통받는 현실 속으로 들어가시며, 제자들에게 믿음과 기도, 그리고 낮아져 섬기는 삶을 가르치십니다.\n\n묵상 질문\n1. "나의 믿음 없는 것을 도와 주소서"라는 아버지의 고백처럼, 내 믿음의 연약함을 정직하게 인정하고 있나요?\n2. 누가 더 큰가를 다투던 제자들처럼, 나도 섬김보다 인정받기를 더 원하고 있지는 않나요?\n3. 내 삶에서 단호하게 끊어내야 할 죄의 영역은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-15', E'변화산 사건과 예수의 가르침 (마가복음 10장)', E'마가복음 10장', E'마가복음 10장은 예루살렘을 향한 여정 가운데 예수님께서 제자들과 사람들에게 하나님 나라의 본질을 가르치시는 장면들을 보여줍니다. 먼저 바리새인들이 이혼에 대해 질문하자, 예수님은 모세의 허락이 "마음의 완악함" 때문이었음을 지적하시며 창조 때의 원리로 돌아가십니다. 하나님이 짝지어 주신 한 몸을 사람이 나누지 말라는 말씀은, 인간의 편의가 아닌 하나님의 창조 질서를 따르라는 가르침입니다.\n\n이어서 제자들이 어린아이들을 꾸짖자 예수님은 오히려 노하셨습니다. "하나님의 나라가 이런 자의 것"이라는 선언은 충격적입니다. 당시 사회에서 무시받던 어린아이처럼 자신을 낮추고 전적으로 의존하는 마음이 바로 하나님 나라에 들어가는 자격이라는 것입니다. 계명을 어려서부터 다 지켰다는 부자 청년의 자신감은 "네 재물을 팔아 가난한 자들에게 주라"는 한 마디 앞에서 무너집니다. 그가 슬픈 기색으로 돌아간 모습은 재물이 주는 안전감이 얼마나 큰 우상이 될 수 있는지를 보여줍니다.\n\n예루살렘으로 올라가는 길에서 예수님은 자신의 고난과 죽음, 부활을 세 번째로 예고하십니다. 그런데 바로 그때 야고보와 요한이 영광의 자리를 요구합니다. 십자가의 길을 가시는 스승 앞에서 제자들은 여전히 세상적 권력을 꿈꾸고 있었던 것입니다. 예수님은 "너희 중에 크고자 하는 자는 섬기는 자가 되라"고 가르치시며, 자신이 온 목적이 "섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 대속물로 주려 함"임을 분명히 하십니다.\n\n여리고의 맹인 바디매오는 사람들의 제지에도 불구하고 더욱 크게 "다윗의 자손이여"라고 외칩니다. 그의 간절함은 예수님의 발걸음을 멈추게 했고, "네 믿음이 너를 구원하였다"는 은혜를 받았습니다. 시력을 회복한 그는 곧바로 예수님을 따랐습니다. 이것이 진정한 제자의 모습입니다. 자신의 부족함을 인정하고, 간절히 부르짖으며, 은혜를 받은 후에는 즉시 따르는 것 - 이것이 하나님 나라에 속한 사람의 반응입니다.', E'오늘의 핵심\n예수님은 하나님 나라의 가치가 세상의 기준과 정반대임을 가르치시며, 섬김과 희생이야말로 참된 위대함의 길임을 몸소 보여주십니다.\n\n묵상 질문\n1. 내가 붙잡고 있는 ''재물''이나 ''지위''가 예수님을 따르는 데 걸림돌이 되고 있지는 않나요?\n2. 어린아이처럼 하나님 앞에 자신을 낮추고 전적으로 의지한다는 것은 구체적으로 어떤 모습일까요?\n3. 바디매오처럼 간절히 예수님을 부르며 도움을 구해야 할 내 삶의 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-17', E'예수의 예루살렘 입성과 대결 (마가복음 11장)', E'마가복음 11장', E'예루살렘을 향한 예수님의 여정이 마침내 그 목적지에 도달합니다. 감람산에서 바라본 성전의 모습은 웅장했지만, 그 안에는 깊은 영적 타락이 자리하고 있었습니다. 예수님은 구약의 예언대로 나귀를 타고 입성하시는데, 이는 전쟁의 왕이 아닌 평화의 왕으로 오심을 보여줍니다. 백성들이 "호산나 다윗의 자손이여"라고 외치며 환영했지만, 그들의 기대와 예수님의 사명 사이에는 큰 간극이 있었습니다.\n\n다음 날 아침, 잎만 무성한 무화과나무를 저주하신 일은 단순한 감정 표출이 아니었습니다. 이스라엘을 상징하는 무화과나무처럼, 겉으로는 종교적 활동이 왕성했지만 참된 열매가 없는 당시 유대교의 실상을 드러내신 것입니다. 이어서 성전에 들어가신 예수님은 "만민이 기도하는 집"을 "강도의 소굴"로 만든 자들을 내쫓으십니다. 이방인의 뜰에서 벌어지는 상업 행위는 이방인들의 예배를 방해했고, 성전을 이용해 부당한 이익을 취하는 종교 지도자들의 탐욕을 보여주었습니다.\n\n종교 지도자들은 예수님께 "무슨 권위로 이런 일을 하느냐"고 따져 묻습니다. 그러나 이들은 진리를 구하는 것이 아니라 자신들의 기득권을 지키려 했을 뿐입니다. 예수님의 역질문 앞에서 "알지 못하겠다"고 답한 그들의 모습은, 백성의 여론만 의식하고 하나님의 뜻에는 무관심한 위선을 드러냅니다.\n\n마른 무화과나무를 보고 놀라는 제자들에게 예수님은 믿음의 기도에 대해 가르치십니다. 그러나 여기서 중요한 것은 "무엇이든 이루어진다"는 약속이 아니라, 하나님의 뜻에 합당한 기도와 용서하는 마음입니다. 성전을 정화하신 예수님이 곧이어 용서를 말씀하신 것은, 참된 예배는 하나님과의 관계뿐 아니라 이웃과의 관계 회복에서 시작됨을 보여줍니다.\n\n오늘 우리의 신앙생활도 잎만 무성한 무화과나무는 아닌지, 기도의 집이 장사하는 곳이 되어있지는 않은지 돌아봅시다. 예수님의 권위는 우리의 편안한 종교생활을 뒤흔들지만, 그것이 바로 참된 열매를 맺는 길입니다.', E'오늘의 핵심\n예수님은 평화의 왕으로 예루살렘에 입성하셔서 열매 없는 종교의 위선을 드러내시고, 성전이 모든 민족을 위한 기도의 집이 되기를 원하십니다.\n\n묵상 질문\n1. 내 신앙생활에서 잎만 무성하고 열매는 없는 영역은 무엇인가요?\n2. 하나님과의 관계에서 ''거래''나 ''장사''하는 마음은 없는지 점검해보셨나요?\n3. 용서하지 못하는 마음이 내 기도를 가로막고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-18', E'예수의 예루살렘 입성과 대결 (마가복음 12장)', E'마가복음 12장', E'마가복음 12장은 예루살렘 성전에서 벌어진 긴장된 대결의 연속입니다. 포도원 농부의 비유로 시작되는 이 장면은 이스라엘 지도자들의 완악함을 적나라하게 드러냅니다. 주인이 보낸 종들을 때리고 죽이며, 마침내 사랑하는 아들까지 죽여버리는 농부들의 모습은 선지자들을 핍박하고 이제 하나님의 아들까지 거부하는 종교 지도자들의 실상을 보여줍니다. 예수님은 "건축자들이 버린 돌이 모퉁이의 머릿돌이 되었다"는 시편 말씀으로 하나님의 역설적인 구원 계획을 선포하셨습니다.\n\n이어지는 세금 논쟁과 부활 논쟁은 예수님을 함정에 빠뜨리려는 시도였지만, 오히려 그분의 지혜를 드러내는 계기가 되었습니다. "가이사의 것은 가이사에게, 하나님의 것은 하나님께"라는 말씀은 단순히 납세의 의무를 넘어, 하나님의 형상으로 지음받은 우리가 마땅히 하나님께 드려야 할 것이 무엇인지를 생각하게 합니다. 부활을 부인하는 사두개인들에게는 "하나님은 죽은 자의 하나님이 아니요 산 자의 하나님"이라는 선언으로 그들의 잘못된 성경 이해를 바로잡으셨습니다.\n\n한 서기관과의 대화에서는 율법의 핵심이 사랑임이 분명히 드러납니다. 하나님 사랑과 이웃 사랑이라는 두 계명이 모든 제사와 예물보다 중요하다는 서기관의 깨달음을 예수님은 기뻐하셨습니다. 그러나 같은 서기관들이 긴 옷을 입고 높은 자리를 탐하며 과부의 가산을 삼키는 위선적 모습도 신랄하게 지적하셨습니다.\n\n마지막 장면에서 가난한 과부가 넣은 두 렙돈은 부자들의 많은 헌금보다 더 큰 가치로 인정받았습니다. 그것은 그녀의 "생활비 전부"였기 때문입니다. 예수님은 액수가 아닌 헌신의 깊이를 보셨고, 남은 것에서가 아닌 전부를 드리는 믿음을 귀하게 여기셨습니다. 이는 곧 십자가에서 자신의 전부를 내어주실 예수님의 희생을 미리 보여주는 아름다운 본보기였습니다.', E'오늘의 핵심\n예루살렘 성전에서 종교 지도자들과 대결하시는 예수님은 그들의 위선을 드러내시고, 참된 신앙은 사랑과 헌신에 있음을 가르치십니다.\n\n묵상 질문\n1. 내가 하나님께서 보내신 메신저나 말씀을 거부하고 있는 영역은 없을까요?\n2. 하나님 사랑과 이웃 사랑이 내 신앙생활에서 실제로 최우선이 되고 있나요?\n3. 과부의 두 렙돈처럼 하나님께 온전히 드려야 할 나의 ''전부''는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-19', E'예수의 예루살렘 입성과 대결 (마가복음 13장)', E'마가복음 13장', E'성전의 화려함에 감탄하는 제자들에게 예수님은 충격적인 선언을 하십니다. "돌 하나도 돌 위에 남지 않고 다 무너뜨려지리라." 유대인들의 자부심이자 신앙의 중심이었던 예루살렘 성전이 완전히 파괴될 것이라는 말씀은, 제자들에게 세상이 무너지는 것과 같은 충격이었을 것입니다. 감람산에서 성전을 바라보시며 예수님은 앞으로 일어날 일들을 차근차근 설명하십니다. 거짓 그리스도의 등장, 전쟁과 지진, 그리고 제자들이 받을 박해까지. 그런데 주목할 것은 예수님이 이 모든 환난을 "재난의 시작"이라고 표현하신다는 점입니다. 마치 해산의 고통이 새 생명의 시작을 알리듯, 이 고난들은 하나님 나라의 완성을 향한 과정임을 암시합니다.\n\n특별히 예수님은 제자들이 공회와 회당에서 재판받고 매질당할 것을 예고하시면서도, 이것이 "증거가 되려 함이라"고 말씀하십니다. 박해받는 그 순간조차도 복음을 전하는 기회가 된다는 것입니다. 더 나아가 "말하는 이는 너희가 아니요 성령이시니라"는 약속을 주십니다. 가장 두렵고 막막한 순간에 성령께서 직접 말씀을 주신다는 이 약속은 얼마나 큰 위로가 되는지요. 예수님은 무화과나무의 비유를 통해 이런 징조들을 분별할 지혜를 주시면서도, 정작 그날과 그때는 "아버지만 아시느니라"고 하십니다. 우리가 알아야 할 것은 그 정확한 시기가 아니라, 언제든 주님을 맞을 준비를 하며 깨어 있는 삶입니다.\n\n"깨어 있으라"는 명령이 이 장에서 네 번이나 반복됩니다. 이는 단순히 잠들지 말라는 의미가 아니라, 영적으로 각성하여 주님의 뜻에 민감하게 반응하며 살라는 말씀입니다. 환난 중에도 복음은 만국에 전파되어야 하고, 끝까지 견디는 자는 구원을 받을 것입니다. 오늘도 우리는 주님의 재림을 기다리며, 맡겨진 사명에 충실한 종으로 살아갑니다.', E'오늘의 핵심\n예수님은 성전 파괴와 종말의 징조들을 예언하시면서, 환난 중에도 복음을 증거하며 깨어 있으라고 명하십니다.\n\n묵상 질문\n1. 내가 의지하고 있는 ''성전''과 같은 것들이 무너질 때, 나는 무엇을 붙잡습니까?\n2. 어려움과 박해 속에서도 복음을 증거할 수 있는 담대함은 어디서 올까요?\n3. ''깨어 있는 삶''이란 구체적으로 어떤 모습일까요? 오늘 내가 실천할 한 가지는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-20', E'세례 요한 탄생', E'누가복음', E'누가는 데오빌로에게 보내는 편지를 시작하면서, 예수 그리스도에 관한 일들을 "근원부터 자세히 미루어 살핀" 후 차례대로 기록한다고 밝힙니다. 그가 전하고자 하는 첫 번째 이야기는 구원 역사의 새로운 장을 여는 두 가지 탄생 예고입니다.\n\n오랜 세월 자녀를 갈망했던 제사장 사가랴와 엘리사벳 부부에게 천사 가브리엘이 나타납니다. 하나님 앞에 의인으로 살았지만 아이를 갖지 못했던 이들에게, 하나님께서는 특별한 소명을 지닌 아들 요한을 약속하십니다. 그러나 사가랴는 자신과 아내의 나이를 생각하며 천사의 말을 의심했고, 그 결과 아이가 태어날 때까지 말을 하지 못하게 됩니다. 이는 단순한 징벌이 아니라, 하나님의 약속이 반드시 이루어질 것임을 보여주는 표징이었습니다.\n\n여섯 달 후, 같은 천사가 갈릴리 나사렛의 한 처녀 마리아에게 나타납니다. 다윗의 자손 요셉과 약혼한 마리아에게 전해진 소식은 더욱 놀라운 것이었습니다. 성령으로 잉태하여 하나님의 아들을 낳으리라는 것입니다. 마리아는 처음에는 당황했지만, "주의 여종이오니 말씀대로 내게 이루어지이다"라고 순종의 고백을 드립니다.\n\n마리아가 엘리사벳을 찾아갔을 때, 태중의 아기 요한이 기쁨으로 뛰놀았고, 성령 충만한 엘리사벳은 마리아와 그 태중의 아기를 축복합니다. 이에 마리아는 장엄한 찬송으로 화답합니다. "내 영혼이 주를 찬양하며"로 시작하는 이 노래는 비천한 자를 높이시고 교만한 자를 낮추시는 하나님의 구원 역사를 노래합니다.\n\n요한의 탄생 후 할례식에서 사가랴는 천사의 지시대로 아이의 이름을 ''요한''이라 짓습니다. 그 순간 그의 입이 열려 하나님을 찬송하게 됩니다. 누가복음은 이렇게 두 가지 기적적인 잉태와 탄생 이야기를 통해, 인간의 불가능을 하나님의 가능으로 바꾸시는 구원의 서막을 열어 보입니다.', E'오늘의 핵심\n하나님께서는 늙은 부부와 처녀를 통해 구원 역사의 새로운 장을 여시며, 인간의 한계를 초월하는 은혜로 당신의 약속을 성취하십니다.\n\n묵상 질문\n1. 내 삶에서 ''불가능''이라고 여기는 영역에도 하나님의 은혜가 임할 수 있음을 믿고 있나요?\n2. 마리아처럼 하나님의 뜻에 순종하는 것을 가로막는 나의 두려움은 무엇인가요?\n3. 하나님의 약속을 의심했던 사가랴처럼, 나도 눈에 보이는 현실만을 의지하고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-21', E'예수의 치유와 교훈 (누가복음 1장)', E'누가복음 1장', E'누가는 그의 복음서를 시작하면서 이 기록이 "처음부터 목격자와 말씀의 일꾼 된 자들이 전하여 준 그대로"(눅 1:2) 정확하고 신뢰할 만한 내용임을 밝힙니다. 그리고 이 복음의 시작은 오랫동안 자녀를 갖지 못했던 늙은 제사장 부부의 이야기로 열립니다.\n\n사가랴와 엘리사벳은 "하나님 앞에 의인"으로 "주의 모든 계명과 규례대로 흠이 없이" 살았던 신실한 부부였습니다. 그러나 그들에게는 자녀가 없었고, 이미 나이가 많아 인간적인 소망조차 품을 수 없는 상황이었습니다. 바로 이때 하나님께서 개입하십니다. 성전에서 분향하던 사가랴에게 천사 가브리엘이 나타나 아들을 낳을 것이며, 그가 "주 앞에 큰 자가 되어" 많은 이스라엘 자손을 하나님께로 돌아오게 할 것이라는 놀라운 소식을 전합니다.\n\n이어서 천사 가브리엘은 갈릴리 나사렛의 처녀 마리아를 찾아갑니다. 평범한 시골 처녀에게 전해진 메시지는 더욱 놀라운 것이었습니다. 성령으로 잉태하여 "지극히 높으신 이의 아들"을 낳을 것이며, 그가 다윗의 왕위를 이어받아 영원한 나라를 다스릴 것이라는 예언이었습니다. 마리아의 반응은 사가랴와 대조적입니다. "주의 여종이오니 말씀대로 내게 이루어지이다"라는 그녀의 고백은 완전한 신뢰와 순종의 표현이었습니다.\n\n마리아가 엘리사벳을 방문했을 때, 엘리사벳 복중의 아이가 기쁨으로 뛰놀며 성령의 역사가 나타납니다. 이에 마리아는 하나님을 찬양하는 노래를 부르는데, 이 찬가는 하나님께서 비천한 자를 높이시고 교만한 자를 낮추시는 구원의 역사를 선포합니다. 누가복음은 이렇게 두 기적적인 잉태와 탄생을 통해 하나님의 구원 역사가 새롭게 시작되고 있음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 인간의 불가능한 상황 속에서 당신의 구원 계획을 이루어 가시며, 비천하고 연약한 자들을 통해 위대한 역사를 시작하십니다.\n\n묵상 질문\n1. 사가랴처럼 의인으로 살면서도 응답받지 못한 기도가 있다면, 하나님의 때를 기다릴 수 있을까요?\n2. 마리아처럼 이해할 수 없는 하나님의 뜻 앞에서도 "말씀대로 이루어지이다"라고 고백할 수 있나요?\n3. 내 삶에서 하나님께서 불가능을 가능으로 바꾸실 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-22', E'예수의 치유와 교훈 (누가복음 2장)', E'누가복음 2장', E'로마 황제 아구스도의 호적 명령이 내려졌을 때, 요셉과 만삭의 마리아는 나사렛에서 베들레헴까지 먼 길을 떠나야 했습니다. 다윗의 후손인 요셉이 조상의 고향으로 돌아가는 이 여정은 단순한 행정 명령에 대한 순종이 아니라, 구약의 예언이 성취되는 하나님의 섭리였습니다. 베들레헴에 도착했을 때 여관에는 그들을 위한 방이 없었고, 아기 예수님은 구유에 누이셨습니다. 창조주이신 하나님의 아들이 가장 낮고 천한 곳에서 태어나신 것입니다.\n\n그날 밤 들판에서 양을 지키던 목자들에게 천사가 나타나 큰 기쁨의 좋은 소식을 전했습니다. "오늘 다윗의 동네에 너희를 위하여 구주가 나셨으니 곧 그리스도 주시니라"(눅 2:11). 당시 목자들은 사회적으로 소외된 계층이었지만, 하나님께서는 바로 이들에게 먼저 구원의 소식을 전하셨습니다. 목자들이 달려가 아기 예수님을 뵈었을 때, 마리아는 이 모든 일을 마음에 새기어 생각했습니다.\n\n정결예식을 위해 성전에 올라간 요셉과 마리아는 경건한 시므온과 선지자 안나를 만났습니다. 성령의 감동을 받은 시므온은 아기 예수를 안고 "내 눈이 주의 구원을 보았사오니"라고 찬송했습니다. 그는 이 아기가 이방의 빛이요 이스라엘의 영광이 될 것이라 선포했습니다. 팔십사 세의 안나 역시 하나님께 감사하며 예루살렘의 속량을 기다리는 모든 사람에게 이 아기에 대해 전했습니다.\n\n열두 살이 되신 예수님은 유월절에 부모와 함께 예루살렘에 올라가셨다가 성전에 남아 율법 선생들과 대화를 나누셨습니다. 사흘 만에 예수님을 찾은 부모님께 "내가 내 아버지 집에 있어야 될 줄을 알지 못하셨나이까"라고 말씀하신 것은, 이미 어린 나이에 자신의 정체성과 사명을 분명히 아셨음을 보여줍니다. 그러나 예수님은 부모와 함께 나사렛으로 돌아가 순종하며 자라셨습니다. 하나님의 아들이신 예수님께서 인간의 성장 과정을 온전히 거치시며 하나님과 사람에게 사랑받는 모습으로 자라가신 것입니다.', E'오늘의 핵심\n하나님의 아들이신 예수님은 가장 낮은 곳에서 태어나 온전한 인간의 삶을 사시며, 모든 사람을 위한 구원자가 되셨습니다.\n\n묵상 질문\n1. 예수님이 구유에 누이신 것을 통해 하나님은 우리에게 어떤 메시지를 주시나요?\n2. 시므온과 안나처럼 오랫동안 기다리며 기도하는 신앙의 자세를 어떻게 배울 수 있을까요?\n3. 예수님이 지혜와 은혜 가운데 자라가신 것처럼, 나는 어떤 영역에서 성장이 필요한가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-24', E'예수의 치유와 교훈 (누가복음 3장)', E'누가복음 3장', E'로마 제국의 통치 아래 놓인 유대 땅에 하나님의 말씀이 임했습니다. 디베료 황제가 통치한 지 15년, 본디오 빌라도가 유대 총독으로 있던 때였습니다. 하나님의 말씀은 예루살렘 성전이 아닌 광야에서, 대제사장이 아닌 사가랴의 아들 요한에게 임했습니다. 이는 이미 선지자 이사야가 예언한 대로였습니다. 광야에서 외치는 자의 소리로 주의 길을 준비하는 사명이 요한에게 주어진 것입니다.\n\n요한의 메시지는 단순하면서도 강력했습니다. 회개하고 그 열매를 맺으라는 것이었습니다. 그는 아브라함의 자손이라는 혈통만으로는 충분하지 않다고 선포했습니다. 하나님께서는 돌들로도 아브라함의 자손을 만드실 수 있기 때문입니다. 이미 심판의 도끼가 나무 뿌리에 놓였으니, 좋은 열매를 맺지 못하는 나무는 찍혀 불에 던져질 것이라고 경고했습니다.\n\n백성들이 구체적으로 무엇을 해야 하는지 물었을 때, 요한의 대답은 실제적이었습니다. 옷 두 벌 있는 자는 없는 자와 나누고, 세리는 정한 세금 외에는 거두지 말며, 군인은 강탈하거나 거짓 고발하지 말라고 했습니다. 이는 단순한 종교적 의식이 아닌 삶의 변화를 요구하는 것이었습니다.\n\n사람들이 요한을 메시아로 생각하기 시작했을 때, 요한은 자신보다 능력이 많으신 분이 오실 것을 분명히 했습니다. 자신은 물로 세례를 베풀지만, 오실 그분은 성령과 불로 세례를 베푸실 것이며, 알곡과 쭉정이를 구별하실 것이라고 선포했습니다.\n\n예수님께서 세례를 받으실 때 놀라운 일이 일어났습니다. 하늘이 열리고 성령이 비둘기 같은 형체로 강림하셨으며, "너는 내 사랑하는 아들이라 내가 너를 기뻐하노라"는 하늘의 음성이 들렸습니다. 삼위일체 하나님께서 공개적으로 나타나신 것입니다. 이어지는 족보는 예수님을 아담까지, 그리고 하나님까지 연결시킵니다. 이는 예수님께서 참 인간이시며 동시에 하나님의 아들이심을 보여줍니다.', E'오늘의 핵심\n세례 요한의 회개 선포와 예수님의 세례는 구원의 새 시대가 시작되었음을 알립니다. 하나님의 아들이 인류를 구원하기 위해 공생애를 시작하신 것입니다.\n\n묵상 질문\n1. 요한이 외친 ''회개의 열매''는 오늘 나의 삶에서 어떤 모습으로 나타나야 할까요?\n2. 예수님의 세례 때 나타난 삼위일체 하나님의 모습이 내게 주는 의미는 무엇인가요?\n3. 혈통이나 종교적 신분이 아닌 진정한 회개와 변화를 통해 하나님께 나아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-25', E'예수의 치유와 교훈 (누가복음 4장)', E'누가복음 4장', E'광야에서 사십 일 동안 금식하신 예수님께 마귀가 찾아와 시험합니다. 첫 번째 시험은 돌을 떡으로 만들라는 육신의 욕구에 관한 것이었고, 두 번째는 천하만국의 영광을 주겠다는 권력의 유혹이었으며, 세 번째는 성전 꼭대기에서 뛰어내리라는 하나님을 시험하는 교만의 시험이었습니다. 예수님께서는 이 모든 시험을 하나님의 말씀으로 물리치셨습니다. 광야의 시험을 이기신 후, 예수님께서는 성령의 능력으로 갈릴리로 돌아가 회당에서 가르치기 시작하십니다.\n\n고향 나사렛의 회당에서 예수님께서는 이사야서를 펼쳐 "주의 성령이 내게 임하셨으니 이는 가난한 자에게 복음을 전하게 하시려고 내게 기름을 부으시고"(눅 4:18)라는 말씀을 읽으신 후, 이 예언이 바로 자신을 통해 성취되었음을 선포하십니다. 처음에는 은혜로운 말씀에 놀라워하던 고향 사람들이 예수님께서 엘리야와 엘리사의 예를 들어 이방인들이 오히려 은혜를 받았음을 말씀하시자 분노하여 예수님을 낭떠러지로 밀어 떨어뜨리려 했습니다. 그러나 예수님께서는 그들 가운데를 지나 가버나움으로 가십니다.\n\n가버나움에서 예수님의 사역은 놀라운 권위로 나타납니다. 회당에서 가르치실 때 사람들이 그 권위 있는 가르침에 놀랐고, 더러운 귀신 들린 사람을 고치시며, 시몬의 장모의 열병을 물리치시고, 해 질 무렵에는 온갖 병자들을 고치십니다. 예수님께서는 한적한 곳에서 기도하신 후 제자들에게 말씀하십니다. 다른 동네에서도 하나님 나라의 복음을 전해야 한다고, 바로 이 일을 위해 보내심을 받았다고 말입니다. 예수님의 공생애는 이렇게 말씀의 권위와 긍휼의 능력으로 시작되었습니다.', E'오늘의 핵심\n예수님께서는 광야의 시험을 하나님의 말씀으로 이기시고, 성령의 능력으로 가난하고 눌린 자들에게 하나님 나라의 복음을 전하는 메시아의 사역을 시작하셨습니다.\n\n묵상 질문\n1. 예수님께서 광야의 시험을 이기신 비결인 하나님의 말씀이 내 삶에서는 어떤 능력이 되고 있나요?\n2. 고향 사람들이 예수님을 배척한 이유는 무엇이며, 나도 선입견으로 하나님의 은혜를 제한하고 있지는 않나요?\n3. 예수님께서 가난하고 병든 자들을 찾아가신 것처럼, 내가 복음을 전해야 할 사람은 누구일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-26', E'훈련과 동행 (누가복음 5장)', E'누가복음 5장', E'게네사렛 호숫가에서 펼쳐지는 장면은 하나님 나라의 새로운 질서가 어떻게 시작되는지를 보여줍니다. 밤새 수고했지만 빈 그물을 씻고 있던 어부들에게 예수님께서 다가오셨습니다. 시몬의 배를 빌려 무리를 가르치신 후, 예수님께서는 깊은 곳으로 가서 그물을 내리라고 명하십니다. 전문 어부의 경험과 상식에는 맞지 않는 말씀이었지만, 시몬은 "말씀에 의지하여"(눅 5:5) 순종합니다. 그 결과는 놀라웠습니다. 그물이 찢어질 정도로 많은 고기가 잡혔고, 이를 목격한 시몬 베드로는 자신의 죄인 됨을 고백하며 무릎을 꿇습니다. 예수님께서는 두려워하는 그에게 이제부터는 사람을 낚는 어부가 될 것이라고 말씀하십니다.\n\n누가복음은 예수님의 사역이 어떻게 소외된 자들에게로 향하는지를 생생하게 전해줍니다. 온몸에 나병이 든 사람을 만지시며 고치시고, 지붕을 뚫고 내려온 중풍병자에게는 먼저 죄 사함을 선포하십니다. 바리새인과 서기관들은 신성모독이라며 분개했지만, 예수님께서는 병을 고치심으로써 죄를 사하는 권세가 자신에게 있음을 증명하셨습니다. 더 나아가 세리 레위를 제자로 부르시고 그의 집에서 세리와 죄인들과 함께 식사하십니다. 종교 지도자들의 비난에 예수님께서는 의사가 건강한 자에게가 아니라 병든 자에게 필요하듯, 자신은 의인이 아닌 죄인을 부르러 오셨다고 선언하십니다.\n\n예수님께서는 새 옷과 낡은 옷, 새 포도주와 낡은 부대의 비유를 통해 하나님 나라의 새로운 질서는 율법주의적 종교 체계와는 근본적으로 다르다는 것을 가르치십니다. 금식과 형식에 매인 종교가 아니라, 신랑 되신 예수님과 함께하는 기쁨의 잔치가 하나님 나라의 본질입니다. 이 새로운 나라는 어부, 나병 환자, 중풍병자, 세리와 같은 주변부 사람들을 통해 확장되어 갑니다. 그들의 삶 속에서 일어나는 변화와 회복이야말로 하나님 나라가 이 땅에 임했다는 가장 확실한 증거였습니다.', E'오늘의 핵심\n예수님께서는 실패한 어부들, 소외된 병자들, 멸시받는 세리들을 찾아가셔서 그들을 하나님 나라의 일꾼으로 부르시고 새로운 삶의 질서 속으로 초대하십니다.\n\n묵상 질문\n1. 밤새 수고했지만 아무것도 얻지 못한 시몬처럼, 내 삶의 어떤 영역에서 예수님의 말씀에 의지해야 할까요?\n2. 예수님께서 죄인과 병든 자를 위해 오셨다고 하셨는데, 나는 정말로 예수님이 필요한 사람임을 인정하고 있나요?\n3. 하나님 나라의 새로운 질서가 내 삶에서 어떻게 나타나기를 원하시는지 기도하며 들어보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-27', E'훈련과 동행 (누가복음 6장)', E'누가복음 6장', E'누가복음 6장에서 예수님은 안식일의 참된 의미와 하나님 나라의 혁명적인 가치를 보여주십니다. \n\n안식일에 밀 이삭을 잘라 먹는 제자들을 비난하는 바리새인들에게, 예수님은 다윗의 예를 들어 응답하십니다. 생명을 위한 필요가 종교적 규정보다 우선한다는 것입니다. 이어서 회당에서 손 마른 사람을 고치시며 "안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐"(눅 6:9)고 물으십니다. 안식일은 생명을 억압하는 날이 아니라 생명을 살리는 날이어야 했습니다.\n\n이러한 대립 후에 예수님은 밤새 기도하시고 열두 제자를 선택하십니다. 종교 지도자들의 거부 앞에서, 예수님은 새로운 하나님 나라의 일꾼들을 세우신 것입니다. 그리고 평지에서 선포하신 말씀은 세상의 가치관을 완전히 뒤집습니다. 가난한 자, 주린 자, 우는 자가 복이 있고, 부요한 자, 배부른 자, 웃는 자에게 화가 있다고 하십니다. \n\n특히 원수 사랑의 명령은 당시로서는 상상할 수 없는 가르침이었습니다. 미워하는 자를 선대하고, 저주하는 자를 축복하며, 모욕하는 자를 위해 기도하라는 말씀은 인간의 본성을 거스르는 것처럼 보입니다. 그러나 예수님은 하나님 아버지께서 은혜를 모르는 자와 악한 자에게도 인자하신 것처럼, 우리도 그런 사랑을 실천하라고 하십니다.\n\n말씀의 마지막 부분에서 예수님은 반석 위에 집을 짓는 비유를 들어주십니다. 듣기만 하고 행하지 않는 신앙은 모래 위의 집과 같습니다. 예수님의 혁명적인 가르침은 단순한 이상이 아니라, 우리가 실제로 살아내야 할 삶의 토대입니다. 안식일의 생명 정신을 회복하고, 원수까지도 사랑하는 하나님 나라의 삶은 예수님의 말씀을 듣고 행할 때 가능합니다.', E'오늘의 핵심\n예수님은 종교적 형식주의를 넘어 생명을 살리는 안식일의 본질을 회복하시고, 원수 사랑이라는 하나님 나라의 혁명적 가치를 우리 삶의 반석으로 삼으라고 가르치십니다.\n\n묵상 질문\n1. 내가 지키고 있는 종교적 관습이 오히려 생명을 억압하고 있지는 않나요?\n2. 나를 미워하거나 상처 준 사람을 위해 진심으로 기도해 본 적이 있나요?\n3. 예수님의 말씀을 듣기만 하고 실천하지 못하는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-28', E'예수의 치유와 교훈 (누가복음 7장)', E'누가복음 7장', E'가버나움에서 예수님은 한 백부장의 믿음을 만나십니다. 로마의 군인이면서도 유대인의 회당을 지어줄 만큼 이스라엘을 사랑했던 그는, 병든 종을 위해 유대인 장로들을 통해 예수님께 도움을 청합니다. 그러나 예수님이 가까이 오시자 그는 놀라운 고백을 보냅니다. "말씀만 하사 내 하인을 낫게 하소서"(눅 7:7). 군인으로서 명령의 권위를 알았던 그는, 예수님의 말씀에 담긴 절대적 권위를 인정했던 것입니다. 예수님은 이스라엘 중에서도 이만한 믿음을 보지 못했다고 감탄하십니다.\n\n나인 성에서는 전혀 다른 만남이 일어납니다. 외아들을 잃은 과부는 아무것도 요청하지 않았습니다. 그저 절망 속에서 장례 행렬을 따라갈 뿐이었습니다. 그런데 예수님이 먼저 그녀를 보시고 불쌍히 여기십니다. 죽음의 권세를 깨뜨리시고 청년을 살려 어머니에게 돌려주십니다. 믿음을 보일 여력조차 없던 이에게, 예수님은 긍휼로 먼저 찾아오신 것입니다.\n\n바리새인 시몬의 집에서는 또 다른 은혜의 장면이 펼쳐집니다. 죄인으로 알려진 한 여인이 눈물로 예수님의 발을 적시고 향유를 붓습니다. 시몬은 속으로 예수님을 의심하지만, 예수님은 오백 데나리온과 오십 데나리온의 빚진 자 비유를 통해 가르치십니다. 많이 용서받은 사람이 많이 사랑한다는 진리였습니다. 그 여인의 눈물과 향유는 자격의 증명이 아니라 용서받은 자의 감격이었습니다.\n\n세 이야기는 하나님 나라의 본질을 보여줍니다. 이방인 백부장, 절망에 빠진 과부, 죄인으로 낙인찍힌 여인 - 당시 종교적 기준으로는 하나님께 나아갈 자격이 없는 사람들입니다. 그러나 예수님은 바로 그들에게 구원과 생명과 용서를 베푸십니다. 하나님 나라는 자격을 갖춘 자의 소유가 아니라, 은혜를 필요로 하는 모든 이에게 열려 있는 곳입니다.\n\n한편 세례 요한조차 옥중에서 의구심을 품고 제자들을 보냅니다. 예수님은 메시아의 표적들 - 맹인이 보고, 못 걷는 자가 걸으며, 죽은 자가 살아나는 일들을 증거로 제시하십니다. 그리고 실족하지 않는 자가 복이 있다고 말씀하십니다. 우리의 기대와 다르게 일하시는 주님을 끝까지 신뢰하는 것이 참된 믿음입니다.', E'오늘의 핵심\n예수님은 종교적 자격과 상관없이 은혜를 필요로 하는 모든 사람에게 구원과 생명과 용서를 베푸시며, 하나님 나라는 바로 그런 은혜의 나라임을 보여주십니다.\n\n묵상 질문\n1. 백부장처럼 "말씀만 하소서"라고 고백할 만큼 주님의 권위를 온전히 인정하는 영역이 내 삶에 있나요?\n2. 나인 과부처럼 아무것도 할 수 없을 때, 먼저 찾아오시는 주님의 긍휼을 경험한 적이 있나요?\n3. 용서받은 감격이 식어가고 있다면, 오늘 주님 앞에 어떤 사랑의 표현을 드릴 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-29', E'예수의 치유와 교훈 (누가복음 8장)', E'누가복음 8장', E'누가복음 8장은 예수님의 갈릴리 사역이 절정에 이르는 시기를 보여줍니다. 예수님은 각 성과 마을에 두루 다니시며 하나님의 나라를 선포하셨고, 열두 제자와 함께 여러 여인들도 동행했습니다. 특히 막달라 마리아, 요안나, 수산나 같은 여인들이 자기 소유로 예수님 일행을 섬겼다는 기록은 당시로서는 파격적인 일이었습니다.\n\n예수님이 들려주신 씨 뿌리는 자의 비유는 하나님 나라의 복음이 어떻게 사람들에게 받아들여지는지를 보여줍니다. 같은 씨앗이지만 떨어진 땅의 상태에 따라 결과가 달라집니다. 길가, 바위, 가시떨기, 좋은 땅 - 이 네 가지 땅은 말씀을 듣는 사람들의 마음 상태를 나타냅니다. 예수님은 "들을 귀 있는 자는 들을지어다"라고 외치시며, 말씀을 듣는 것뿐 아니라 어떻게 듣느냐가 중요함을 가르치십니다.\n\n이어지는 장면들은 예수님의 권위를 다양하게 보여줍니다. 갈릴리 호수에서 광풍을 잠잠케 하신 일은 자연까지도 다스리시는 창조주의 권세를 드러냅니다. 제자들은 "그가 누구이기에 바람과 물을 명하매 순종하는가"라며 경외감에 사로잡힙니다. 거라사 지방에서 귀신 들린 사람을 고치신 일은 영적 세계에 대한 주권을, 혈루증 여인과 야이로의 딸을 고치신 일은 질병과 죽음을 이기시는 생명의 주님이심을 증거합니다.\n\n특별히 주목할 점은 예수님께서 각 사람을 대하시는 방식입니다. 무덤 사이에 거하던 귀신 들린 사람을 인격적으로 대하시고, 12년간 혈루증으로 고통받던 여인의 떨리는 손길을 외면하지 않으시며, 죽은 소녀를 향해 "아이야 일어나라"고 부드럽게 말씀하십니다. 예수님은 단순히 기적을 행하시는 분이 아니라, 한 영혼 한 영혼을 귀하게 여기시는 목자이십니다.', E'오늘의 핵심\n예수님은 말씀과 자연과 영적 세계와 생명을 다스리시는 권세를 가지셨지만, 그 능력을 상처받고 소외된 사람들을 회복시키는 데 사용하시는 사랑의 주님이십니다.\n\n묵상 질문\n1. 나는 하나님의 말씀을 어떤 마음 밭으로 받고 있으며, 더 좋은 땅이 되려면 무엇이 필요할까요?\n2. 인생의 광풍 속에서 "너희 믿음이 어디 있느냐"고 물으시는 예수님께 어떻게 응답하시겠습니까?\n3. 예수님이 거라사의 귀신 들린 사람에게 "집으로 돌아가 전파하라"고 하신 것처럼, 내가 경험한 은혜를 누구에게 전할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-31', E'약한 자의 이웃 (누가복음 9장)', E'누가복음 9장', E'누가복음 9장은 예수님께서 제자들에게 능력과 권위를 주시며 하나님 나라 사역에 동참시키시는 장면으로 시작됩니다. 귀신을 제어하고 병을 고치는 능력을 받은 제자들은 각 마을로 흩어져 복음을 전하고 병자를 치유합니다. 그런데 놀랍게도 예수님은 이 파송에서 지팡이도, 배낭도, 양식도, 돈도, 여벌 옷도 가지지 말라고 명하십니다. 철저히 무장해제된 모습으로 가라는 것입니다. 이는 제자들이 의지해야 할 것이 자신들의 준비물이 아니라 오직 하나님의 공급하심임을 가르치는 예수님의 교육 방법이었습니다.\n\n이어지는 오병이어의 기적은 이 교훈을 더욱 선명하게 보여줍니다. 빈들에서 오천 명이 넘는 무리 앞에 놓인 것은 떡 다섯 개와 물고기 두 마리뿐이었습니다. 제자들의 계산으로는 턱없이 부족한 양이었지만, 예수님의 축사하심을 통해 모든 사람이 배불리 먹고도 열두 바구니가 남는 풍성함을 경험합니다. 부족함 속에서 드러나는 하나님의 충만하심, 이것이 하나님 나라의 경제학입니다.\n\n그러나 변화산에서 예수님의 영광을 목격하고, 귀신 들린 아이를 고치시는 능력을 보면서도 제자들 사이에서는 "누가 크냐"는 논쟁이 일어납니다. 하나님 나라의 능력을 경험하면서도 여전히 세상의 서열 의식에 사로잡혀 있는 것입니다. 예수님은 어린아이를 곁에 세우시며 "너희 모든 사람 중에 가장 작은 그가 큰 자"라고 선언하십니다. \n\n이 말씀은 단순히 겸손하라는 도덕적 교훈이 아닙니다. 하나님 나라의 질서는 세상과 정반대라는 혁명적 선언입니다. 능력과 권위를 받았다고 해서 그것이 자기를 높이는 도구가 되어서는 안 됩니다. 오히려 그 능력은 가장 작은 자를 섬기고, 소외된 자를 품으며, 연약한 자의 이웃이 되는 데 사용되어야 합니다. 예수님께서 친히 종의 모습으로 오셔서 섬기신 것처럼 말입니다.', E'오늘의 핵심\n예수님은 제자들에게 능력과 권위를 주시면서도 철저한 의존과 섬김의 자세를 요구하시며, 하나님 나라의 위대함은 작은 자 됨에 있음을 가르치십니다.\n\n묵상 질문\n1. 내가 가진 능력과 재능을 자기 영광이 아닌 섬김을 위해 사용하고 있나요?\n2. 부족함 속에서도 하나님의 공급하심을 신뢰하며 나아간 경험이 있나요?\n3. 오늘 내 곁의 ''가장 작은 자''는 누구이며, 어떻게 그를 섬길 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-01', E'약한 자의 이웃 (누가복음 10장)', E'누가복음 10장', E'예수님께서는 칠십 명의 제자를 둘씩 짝지어 각 동네로 파송하십니다. 이는 앞서 열두 제자를 파송하신 것과 더불어 하나님 나라의 확장을 위한 본격적인 선교 사역의 시작을 보여줍니다. 주님은 제자들에게 "추수할 것은 많되 일꾼이 적으니"(눅 10:2)라고 말씀하시며, 추수하는 주인에게 일꾼을 보내 달라고 기도하라 하십니다. 동시에 그들을 어린 양을 이리 가운데로 보내는 것과 같다고 표현하시며, 전대나 배낭 없이 오직 하나님의 공급하심만을 의지하여 나아가라고 명령하십니다.\n\n제자들이 기쁨으로 돌아와 귀신들도 항복했다고 보고할 때, 예수님은 더 중요한 것을 가르쳐 주십니다. 귀신을 제어하는 권능보다 그들의 이름이 하늘에 기록된 것으로 기뻐하라는 것입니다. 이어서 어느 율법교사가 영생을 얻는 방법을 묻자, 예수님은 선한 사마리아인의 비유를 통해 참된 이웃 사랑의 의미를 가르치십니다. 유대인들이 멸시하던 사마리아인이 오히려 강도 만난 자의 진정한 이웃이 되었다는 이 비유는, 종교적 신분이나 지위가 아닌 실천적 사랑이 영생의 길임을 보여줍니다.\n\n마르다와 마리아의 집을 방문하신 일화는 또 다른 중요한 교훈을 담고 있습니다. 분주하게 접대 준비를 하던 마르다와 달리, 마리아는 주님의 발치에 앉아 말씀을 들었습니다. 예수님은 마리아가 "좋은 편"을 택했다고 말씀하시며, 주님과의 친밀한 교제와 말씀 듣는 것이 우선되어야 함을 가르치십니다. 하나님 나라의 일꾼으로 파송받기 전에, 먼저 주님의 발치에 앉아 그분의 음성을 듣는 것이 제자도의 기초임을 보여주는 것입니다.', E'오늘의 핵심\n예수님은 제자들을 하나님 나라의 일꾼으로 파송하시면서, 하늘에 이름이 기록된 구원의 기쁨과 실천적 사랑, 그리고 말씀을 듣는 것의 중요성을 가르치십니다.\n\n묵상 질문\n1. 나는 사역의 열매보다 구원받은 은혜를 더 귀하게 여기며 살아가고 있나요?\n2. 종교적 의무감이 아닌 진정한 사랑으로 이웃을 섬기고 있나요?\n3. 바쁜 일상 속에서도 주님의 발치에 앉아 말씀을 듣는 시간을 우선순위에 두고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-02', E'예수의 가르침과 이적 (누가복음 11장)', E'누가복음 11장', E'제자들이 예수님께 기도를 가르쳐 달라고 요청하자, 예수님께서는 하나님을 "아버지"라 부르며 시작하는 기도를 가르쳐 주십니다. 율법의 전통 속에서 하나님의 거룩하심만을 강조하던 유대인들에게, 하나님을 친밀한 아버지로 부르라는 가르침은 혁명적인 것이었습니다. 이어서 예수님께서는 밤중에 찾아온 친구의 비유를 통해 끈질긴 간구의 중요성을 보여주십니다. 하나님께서는 우리의 간절한 기도에 응답하시며, 악한 부모도 자녀에게 좋은 것을 줄 줄 아는데 하물며 하늘 아버지께서 구하는 자에게 성령을 주시지 않겠느냐고 말씀하십니다.\n\n예수님께서 벙어리 귀신을 쫓아내시자 일부 사람들은 바알세불의 힘을 빌렸다고 비난합니다. 그러나 예수님께서는 사탄의 나라가 스스로 분쟁하면 설 수 없다는 논리로 그들의 주장을 반박하시고, 하나님의 나라가 이미 임했음을 선포하십니다. 한 여인이 예수님의 어머니를 축복하자, 예수님께서는 "오히려 하나님의 말씀을 듣고 지키는 자가 복이 있느니라"(눅 11:28)고 말씀하시며 진정한 복의 의미를 가르치십니다.\n\n바리새인의 집에 초대받은 예수님께서는 손을 씻지 않고 식사하신 것을 문제 삼는 그들에게 날카로운 책망을 하십니다. 겉은 깨끗이 하면서 속은 탐욕과 악독으로 가득한 위선, 십일조는 철저히 드리면서 정의와 하나님 사랑은 소홀히 하는 형식주의, 명예와 인정받기를 좋아하는 교만함을 지적하십니다. 율법교사들에게도 지기 어려운 짐을 다른 사람에게 지우면서 자신들은 손가락 하나 대지 않는 위선을 꾸짖으십니다. 예수님의 이러한 책망은 종교적 외식과 형식주의에 빠진 당시 종교 지도자들의 실상을 적나라하게 드러내며, 참된 신앙이 무엇인지를 분명히 보여줍니다.', E'오늘의 핵심\n예수님께서는 하나님을 아버지로 부르는 친밀한 기도를 가르치시고, 종교적 형식주의와 위선을 날카롭게 책망하시며 마음의 진실함과 하나님 사랑의 실천을 강조하십니다.\n\n묵상 질문\n1. 내 기도가 형식적인 반복이 아니라 아버지와의 진실한 대화가 되고 있나요?\n2. 신앙의 겉모습은 그럴듯하지만 내면의 탐욕이나 교만은 없는지 돌아봅시다.\n3. 하나님의 말씀을 듣기만 하지 않고 삶으로 실천하기 위해 오늘 무엇을 할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-03', E'예수의 가르침과 이적 (누가복음 12장)', E'누가복음 12장', E'무리 수만 명이 모여들어 서로 밟힐 지경이 되었을 때, 예수님께서는 제자들에게 먼저 중요한 가르침을 주십니다. 바리새인들의 누룩, 곧 외식을 주의하라는 경고로 시작하신 말씀은 참된 신앙의 본질이 무엇인지 깨우쳐 줍니다. 겉으로 드러나는 경건의 모습이 아니라, 하나님 앞에서의 진실함이 중요함을 가르치시는 것입니다. 예수님은 숨겨진 것이 모두 드러날 것이며, 어둠 속에서 한 말이 빛 가운데 들릴 것임을 선포하십니다.\n\n이어서 예수님께서는 참으로 두려워해야 할 대상이 누구인지 분명히 밝히십니다. 몸은 죽여도 그 이상 아무것도 할 수 없는 사람이 아니라, 죽인 후에 지옥에 던질 권세를 가지신 하나님을 두려워해야 한다는 것입니다. 동시에 이 두려우신 하나님은 참새 한 마리도 잊지 않으시고, 우리의 머리카락까지 세신 바 되었을 만큼 세심하게 돌보시는 사랑의 하나님이심을 보여주십니다.\n\n무리 중 한 사람이 유산 분배 문제로 예수님께 도움을 청했을 때, 예수님은 어리석은 부자의 비유를 통해 참된 부요함이 무엇인지 가르치십니다. 곡식을 쌓을 곳간을 더 크게 짓고 안일함에 빠진 부자는 그날 밤 생명을 잃게 됩니다. 이 비유는 생명이 소유의 넉넉함에 있지 않으며, 하나님께 대하여 부요한 삶이 얼마나 중요한지를 일깨워줍니다.\n\n예수님께서는 제자들에게 염려하지 말라는 위로의 말씀을 주십니다. 까마귀도 먹이시고 백합화도 입히시는 하나님께서 하물며 그분의 자녀들을 돌보지 않으시겠냐는 것입니다. "너희는 무엇을 먹을까 무엇을 마실까 하여 구하지 말며 근심하지도 말라"(눅 12:29)고 하시며, 오직 하나님의 나라를 구하라고 명하십니다. 주인을 기다리는 종들의 비유를 통해서는 늘 깨어 준비하고 있어야 함을 가르치시며, 맡은 것에 충성하는 지혜로운 청지기의 자세를 강조하십니다.', E'오늘의 핵심\n예수님께서는 외식이 아닌 진실한 신앙, 세상의 부가 아닌 하나님께 대한 부요함, 염려 대신 하나님 나라를 구하는 삶의 우선순위를 가르치십니다.\n\n묵상 질문\n1. 나의 신앙생활 중에 남의 시선을 의식하는 외식적인 부분은 없나요?\n2. 물질적 안정을 추구하면서 정작 하나님께 대해 부요하지 못한 영역은 무엇인가요?\n3. 하나님 나라를 먼저 구하는 삶을 위해 오늘 내려놓아야 할 염려는 무엇일까요?');
